HTML = '<!DOCTYPE html>\n<html lang="hi">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>वेद ज्ञान — Veda Gyan</title>\n<link href="https://fonts.googleapis.com/css2?family=Tiro+Devanagari+Sanskrit:ital@0;1&family=Noto+Sans+Devanagari:wght@300;400;500;600;700&family=Inter:wght@300;400;500;600;700&display=swap" rel="stylesheet">\n<style>\n/* ── ROOT ── */\n:root{\n  --s:#E8621A;--sl:#FDF0E8;--g:#C8900A;--gl:#FDF6E3;\n  --cream:#FAF6EF;--ink:#1C1409;--soft:#4A3728;--muted:#8B7355;\n  --bd:rgba(200,144,10,.2);--bds:rgba(200,144,10,.45);\n  --w:#fff;--r:14px;--rs:9px;--fs:14px;\n  --shadow:0 2px 12px rgba(0,0,0,.07);\n  --shadow-lg:0 8px 32px rgba(0,0,0,.12);\n}\n*{box-sizing:border-box;margin:0;padding:0}\nhtml{scroll-behavior:smooth}\nbody{font-family:\'Noto Sans Devanagari\',\'Inter\',sans-serif;background:var(--cream);color:var(--ink);min-height:100vh;font-size:var(--fs);overflow-x:hidden}\n.en body,.en p,.en h1,.en h2,.en h3,.en h4,.en .badge,.en .chip,.en small{font-family:\'Inter\',sans-serif}\n\n/* ── ANIMATIONS ── */\n@keyframes fadeUp{from{opacity:0;transform:translateY(16px)}to{opacity:1;transform:translateY(0)}}\n@keyframes pulse{0%,100%{opacity:1}50%{opacity:.6}}\n@keyframes shimmer{0%{background-position:-400px 0}100%{background-position:400px 0}}\n@keyframes spin{to{transform:rotate(360deg)}}\n@keyframes pop{0%{transform:scale(.85);opacity:0}80%{transform:scale(1.05)}100%{transform:scale(1);opacity:1}}\n@keyframes glow{0%,100%{box-shadow:0 0 8px rgba(232,98,26,.3)}50%{box-shadow:0 0 20px rgba(232,98,26,.6)}}\n.fade-up{animation:fadeUp .35s ease both}\n.pop{animation:pop .25s ease both}\n.card-enter{animation:fadeUp .3s ease both}\n\n/* ── HEADER ── */\n.header{\n  background:linear-gradient(135deg,#1C0A02 0%,#3D1A05 60%,#1C0A02 100%);\n  border-bottom:1px solid rgba(200,144,10,.3);\n  padding:.9rem 1.5rem;display:flex;align-items:center;gap:12px;\n  position:sticky;top:0;z-index:300;flex-wrap:wrap;\n  box-shadow:0 2px 20px rgba(0,0,0,.3);\n}\n.header-om{\n  font-family:\'Tiro Devanagari Sanskrit\',serif;\n  font-size:34px;color:#FFD700;line-height:1;\n  text-shadow:0 0 20px rgba(255,215,0,.5);\n  animation:glow 3s ease-in-out infinite;\n}\n.header-text h1{font-size:18px;font-weight:700;color:#FFE8C0;letter-spacing:.5px}\n.header-text p{font-size:11px;color:rgba(255,215,0,.6);margin-top:1px}\n.header-tools{margin-left:auto;display:flex;gap:6px;align-items:center;flex-wrap:wrap}\n.tool-btn{\n  padding:5px 11px;border-radius:20px;\n  border:1px solid rgba(255,215,0,.3);\n  background:rgba(255,255,255,.08);\n  cursor:pointer;font-size:12px;color:#FFE8C0;\n  transition:all .2s;font-family:inherit;white-space:nowrap;backdrop-filter:blur(8px);\n}\n.tool-btn:hover,.tool-btn.active{background:rgba(255,215,0,.2);border-color:rgba(255,215,0,.6);color:#FFD700}\n\n/* ── NAV ── */\n.main-nav{\n  display:flex;gap:0;\n  background:var(--w);\n  border-bottom:1px solid var(--bd);\n  position:sticky;top:57px;z-index:200;\n  overflow-x:auto;box-shadow:var(--shadow);\n}\n.main-nav::-webkit-scrollbar{height:0}\n.nav-tab{\n  padding:10px 16px;border:none;background:none;cursor:pointer;\n  font-size:12px;color:var(--muted);font-family:inherit;\n  border-bottom:2px solid transparent;white-space:nowrap;\n  transition:all .2s;position:relative;\n}\n.nav-tab::after{content:\'\';position:absolute;bottom:-1px;left:50%;right:50%;height:2px;background:var(--s);transition:all .2s;border-radius:2px}\n.nav-tab.active::after{left:0;right:0}\n.nav-tab.active{color:var(--s);font-weight:600}\n.nav-tab:hover{color:var(--ink)}\n.nav-badge{\n  display:inline-block;background:var(--s);color:#fff;\n  font-size:9px;border-radius:10px;padding:1px 5px;margin-left:4px;vertical-align:middle;\n}\n\n.container{max-width:940px;margin:0 auto;padding:1.4rem}\n\n/* ── SEARCH ── */\n.search-wrap{position:relative;margin-bottom:1.2rem}\n.search-input{\n  width:100%;padding:11px 16px 11px 42px;\n  border:1.5px solid var(--bds);border-radius:var(--r);\n  background:var(--w);font-size:13px;font-family:inherit;\n  outline:none;transition:all .2s;box-shadow:var(--shadow);\n}\n.search-input:focus{border-color:var(--g);box-shadow:0 0 0 3px rgba(200,144,10,.1)}\n.search-icon{position:absolute;left:14px;top:50%;transform:translateY(-50%);color:var(--muted);font-size:16px}\n.search-results{\n  background:var(--w);border:1px solid var(--bds);\n  border-radius:var(--rs);margin-top:4px;display:none;\n  max-height:260px;overflow-y:auto;box-shadow:var(--shadow-lg);\n  position:absolute;width:100%;z-index:100;\n}\n.sr-item{padding:10px 14px;cursor:pointer;border-bottom:1px solid var(--bd);font-size:13px;display:flex;justify-content:space-between;align-items:center;transition:background .15s}\n.sr-item:hover{background:var(--gl)}\n.sr-item:last-child{border-bottom:none}\n.sr-tag{font-size:10px;color:var(--muted);background:var(--cream);padding:2px 8px;border-radius:10px;flex-shrink:0;margin-left:8px}\n\n/* ── DAILY VERSE ── */\n.daily-banner{\n  background:linear-gradient(135deg,#1C0A02 0%,#4A1C08 50%,#2C0E04 100%);\n  border-radius:var(--r);padding:1.4rem 1.6rem;margin-bottom:1.2rem;\n  color:#fff;position:relative;overflow:hidden;\n  box-shadow:var(--shadow-lg);border:1px solid rgba(200,144,10,.3);\n}\n.daily-banner::before{\n  content:\'ॐ\';position:absolute;right:-10px;top:50%;transform:translateY(-50%);\n  font-size:100px;opacity:.05;font-family:\'Tiro Devanagari Sanskrit\',serif;\n  pointer-events:none;\n}\n.daily-banner::after{\n  content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;\n  background:linear-gradient(45deg,transparent 30%,rgba(255,215,0,.03) 50%,transparent 70%);\n  animation:shimmer 4s linear infinite;background-size:800px 100%;\n}\n.daily-label{font-size:10px;letter-spacing:2px;color:rgba(255,215,0,.7);text-transform:uppercase;margin-bottom:8px;display:flex;align-items:center;gap:6px}\n.daily-dot{width:6px;height:6px;background:#FFD700;border-radius:50%;animation:pulse 2s infinite}\n.daily-shloka{font-family:\'Tiro Devanagari Sanskrit\',serif;font-size:16px;line-height:2;color:#FFE8C0;margin-bottom:10px}\n.daily-meaning{font-size:13px;color:rgba(255,255,255,.78);line-height:1.75}\n.daily-footer{display:flex;justify-content:space-between;align-items:center;margin-top:10px}\n.daily-source{font-size:11px;color:rgba(255,215,0,.5);font-style:italic}\n.daily-actions{display:flex;gap:8px}\n.daily-btn{\n  background:rgba(255,215,0,.12);border:1px solid rgba(255,215,0,.3);\n  color:#FFD700;border-radius:20px;padding:4px 12px;font-size:11px;\n  cursor:pointer;font-family:inherit;transition:all .2s;\n}\n.daily-btn:hover{background:rgba(255,215,0,.22)}\n\n/* ── PROGRESS BAR ── */\n.progress-wrap{margin-bottom:1.2rem}\n.progress-label{display:flex;justify-content:space-between;font-size:11px;color:var(--muted);margin-bottom:5px}\n.progress-bar{height:4px;background:var(--bd);border-radius:2px;overflow:hidden}\n.progress-fill{height:100%;border-radius:2px;transition:width .5s cubic-bezier(.4,0,.2,1)}\n\n/* ── VEDA TABS ── */\n.veda-tabs{display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin-bottom:1.2rem}\n.tab-btn{\n  background:var(--w);border:1.5px solid var(--bd);border-radius:var(--r);\n  padding:13px 8px;cursor:pointer;text-align:center;\n  transition:all .22s cubic-bezier(.4,0,.2,1);font-family:inherit;\n  box-shadow:var(--shadow);position:relative;overflow:hidden;\n}\n.tab-btn::before{\n  content:\'\';position:absolute;inset:0;background:linear-gradient(135deg,transparent,rgba(255,255,255,.4));\n  opacity:0;transition:opacity .2s;\n}\n.tab-btn:hover{transform:translateY(-2px);box-shadow:var(--shadow-lg)}\n.tab-btn:hover::before{opacity:1}\n.tab-btn.active{border-width:2px;transform:translateY(-1px);box-shadow:var(--shadow-lg)}\n.tab-icon{font-size:24px;display:block;margin-bottom:5px}\n.tab-name{font-size:13px;font-weight:600;color:var(--ink)}\n.tab-sub{font-size:10px;color:var(--muted);margin-top:2px}\n.tab-bm{font-size:10px;margin-top:4px;min-height:14px}\n\n/* ── CARDS ── */\n.card{\n  background:var(--w);border:1px solid var(--bd);\n  border-radius:var(--r);padding:1.4rem;margin-bottom:1rem;\n  box-shadow:var(--shadow);transition:box-shadow .2s;\n}\n.card:hover{box-shadow:var(--shadow-lg)}\n.card-header{\n  display:flex;gap:16px;align-items:flex-start;\n  padding-bottom:1.2rem;border-bottom:1px solid var(--bd);margin-bottom:1.2rem;\n}\n.veda-emblem{\n  width:58px;height:58px;border-radius:50%;\n  display:flex;align-items:center;justify-content:center;\n  font-size:26px;flex-shrink:0;box-shadow:0 4px 12px rgba(0,0,0,.1);\n}\n.veda-meta h2{font-size:19px;font-weight:700;margin-bottom:5px}\n.veda-meta p{font-size:13px;color:var(--soft);line-height:1.85}\n.badges{display:flex;flex-wrap:wrap;gap:6px;margin-top:8px}\n.badge{font-size:11px;padding:3px 10px;border-radius:20px;font-weight:500}\n.veda-actions{display:flex;gap:8px;margin-top:8px}\n.icon-btn{\n  background:var(--cream);border:1px solid var(--bds);\n  border-radius:8px;padding:5px 10px;cursor:pointer;font-size:13px;\n  transition:all .15s;font-family:inherit;color:var(--muted);\n}\n.icon-btn:hover{background:var(--gl);color:var(--g)}\n.icon-btn.active{background:var(--gl);color:var(--g);border-color:var(--g)}\n\n/* ── FACTS ── */\n.facts-row{display:grid;grid-template-columns:repeat(3,1fr);gap:8px;margin-bottom:1.2rem}\n.fact-box{\n  border-radius:var(--rs);padding:12px;text-align:center;\n  transition:transform .15s;cursor:default;\n}\n.fact-box:hover{transform:scale(1.02)}\n.fact-num{font-size:22px;font-weight:700;font-family:\'Inter\',sans-serif}\n.fact-label{font-size:10px;color:var(--muted);margin-top:3px;line-height:1.4}\n\n/* ── SECTION NAV ── */\n.section-label{font-size:11px;color:var(--muted);font-weight:600;letter-spacing:.8px;margin-bottom:10px;text-transform:uppercase}\n.section-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-bottom:1.2rem}\n.sec-card{\n  background:var(--cream);border:1.5px solid var(--bd);border-radius:var(--rs);\n  padding:11px 8px;cursor:pointer;transition:all .2s;text-align:center;\n  font-family:inherit;position:relative;overflow:hidden;\n}\n.sec-card:hover{transform:translateY(-1px);box-shadow:var(--shadow)}\n.sec-card.active{border-width:2px;background:var(--w)}\n.sec-card-icon{font-size:18px;margin-bottom:4px}\n.sec-card-name{font-size:11px;font-weight:700;color:var(--ink)}\n.sec-card-sub{font-size:10px;color:var(--muted);margin-top:2px}\n\n/* ── DETAIL BOXES ── */\n.detail-box{\n  background:var(--cream);border-left:3px solid;\n  border-radius:0 var(--rs) var(--rs) 0;padding:1rem 1.2rem;\n}\n.detail-box h3{font-size:14px;font-weight:700;margin-bottom:8px}\n.detail-box p{font-size:13px;color:var(--soft);line-height:1.9}\n\n/* ── UPANISHAD SECTION ── */\n.up-hero{\n  background:linear-gradient(135deg,#1C0A02,#3D1A05);\n  border-radius:var(--r);padding:1.6rem;margin-bottom:1.2rem;\n  color:#fff;position:relative;overflow:hidden;\n}\n.up-hero::before{content:\'🧘\';position:absolute;right:20px;bottom:-10px;font-size:80px;opacity:.08}\n.up-hero h2{font-size:20px;font-weight:700;color:#FFE8C0;margin-bottom:6px}\n.up-hero p{font-size:13px;color:rgba(255,255,255,.7);line-height:1.75;max-width:600px}\n.up-stats{display:flex;gap:20px;margin-top:14px;flex-wrap:wrap}\n.up-stat{text-align:center}\n.up-stat-num{font-size:22px;font-weight:700;color:#FFD700;font-family:\'Inter\',sans-serif}\n.up-stat-label{font-size:10px;color:rgba(255,215,0,.6);margin-top:2px}\n\n/* ── UPANISHAD FILTER TABS ── */\n.up-filter{display:flex;gap:8px;margin-bottom:1.2rem;overflow-x:auto;padding-bottom:4px}\n.up-filter::-webkit-scrollbar{height:0}\n.up-filter-btn{\n  padding:7px 16px;border-radius:20px;border:1.5px solid var(--bds);\n  background:var(--w);cursor:pointer;font-size:12px;font-family:inherit;\n  white-space:nowrap;transition:all .2s;font-weight:500;\n}\n.up-filter-btn:hover{background:var(--gl)}\n.up-filter-btn.active{color:#fff;border-color:transparent;font-weight:600}\n\n/* ── UPANISHAD CARDS ── */\n.up-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:12px;margin-bottom:1.2rem}\n.up-card{\n  background:var(--w);border:1.5px solid var(--bd);border-radius:var(--r);\n  padding:1.2rem;cursor:pointer;transition:all .22s;\n  position:relative;overflow:hidden;box-shadow:var(--shadow);\n}\n.up-card::before{\n  content:\'\';position:absolute;top:0;left:0;right:0;height:3px;\n  opacity:0;transition:opacity .2s;\n}\n.up-card:hover{transform:translateY(-3px);box-shadow:var(--shadow-lg)}\n.up-card:hover::before,.up-card.active::before{opacity:1}\n.up-card.active{border-width:2px;transform:translateY(-1px)}\n.up-card-top{display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:8px}\n.up-card-name{font-size:14px;font-weight:700}\n.up-card-veda{font-size:10px;padding:2px 8px;border-radius:10px;font-weight:600}\n.up-card-sub{font-size:11px;color:var(--muted);margin-bottom:8px}\n.up-card-teaser{font-size:12px;color:var(--soft);line-height:1.6}\n.up-card-mv{\n  margin-top:10px;padding:8px 10px;border-radius:var(--rs);\n  font-family:\'Tiro Devanagari Sanskrit\',serif;font-size:13px;\n}\n.up-card-badges{display:flex;gap:5px;flex-wrap:wrap;margin-top:8px}\n.up-mini-badge{font-size:10px;padding:2px 8px;border-radius:10px;font-weight:500}\n\n/* ── UPANISHAD DEEP DIVE ── */\n.up-deep{\n  background:var(--w);border:1px solid var(--bd);border-radius:var(--r);\n  overflow:hidden;box-shadow:var(--shadow-lg);margin-bottom:1.2rem;\n  animation:fadeUp .3s ease;\n}\n.up-deep-header{padding:1.4rem 1.4rem 1rem;border-bottom:1px solid var(--bd)}\n.up-deep-title{font-size:18px;font-weight:700;margin-bottom:4px}\n.up-deep-meta{font-size:12px;color:var(--muted);display:flex;gap:12px;flex-wrap:wrap}\n.up-deep-meta span{display:flex;align-items:center;gap:4px}\n.up-tabs{display:flex;border-bottom:1px solid var(--bd);overflow-x:auto}\n.up-tab{\n  padding:10px 16px;border:none;background:none;cursor:pointer;\n  font-size:12px;font-family:inherit;color:var(--muted);\n  border-bottom:2px solid transparent;white-space:nowrap;transition:all .2s;\n}\n.up-tab.active{color:var(--s);border-bottom-color:var(--s);font-weight:600}\n.up-tab:hover{color:var(--ink)}\n.up-content{padding:1.4rem}\n.up-story{font-size:13px;color:var(--soft);line-height:1.95;margin-bottom:1rem}\n.up-story strong{color:var(--ink);font-weight:600}\n.up-mv-box{\n  background:linear-gradient(135deg,#1C0A02,#3D1A05);\n  border-radius:var(--rs);padding:1.2rem 1.4rem;margin-bottom:1rem;\n  position:relative;overflow:hidden;\n}\n.up-mv-box::before{content:\'❝\';position:absolute;top:8px;left:10px;font-size:30px;opacity:.08;color:#FFD700}\n.up-mv-sanskrit{font-family:\'Tiro Devanagari Sanskrit\',serif;font-size:20px;color:#FFD700;margin-bottom:6px;line-height:1.6}\n.up-mv-trans{font-size:13px;color:rgba(255,255,255,.75);margin-bottom:4px}\n.up-mv-source{font-size:11px;color:rgba(255,215,0,.5);font-style:italic}\n.up-lesson-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:10px;margin-bottom:1rem}\n.up-lesson{background:var(--cream);border-radius:var(--rs);padding:12px 14px;border-left:3px solid}\n.up-lesson-icon{font-size:18px;margin-bottom:5px}\n.up-lesson-title{font-size:12px;font-weight:700;margin-bottom:4px}\n.up-lesson-text{font-size:12px;color:var(--soft);line-height:1.65}\n.up-story-box{\n  background:var(--cream);border:1px solid var(--bd);border-radius:var(--rs);\n  padding:1.2rem;margin-bottom:1rem;\n}\n.up-story-box h4{font-size:14px;font-weight:700;margin-bottom:10px;display:flex;align-items:center;gap:8px}\n.up-story-para{font-size:13px;color:var(--soft);line-height:1.9;margin-bottom:10px}\n.up-story-para:last-child{margin-bottom:0}\n.up-dialogue{\n  background:var(--w);border-radius:var(--rs);padding:12px 14px;\n  margin:10px 0;border-left:3px solid var(--bds);font-size:13px;color:var(--soft);line-height:1.8;\n  font-style:italic;\n}\n.up-verse-box{\n  background:var(--gl);border:1px solid var(--bds);border-radius:var(--rs);\n  padding:1.2rem;margin-bottom:1rem;\n}\n.up-verse-sanskrit{font-family:\'Tiro Devanagari Sanskrit\',serif;font-size:15px;color:var(--ink);line-height:2;margin-bottom:8px}\n.up-verse-divider{height:1px;background:var(--bds);margin-bottom:8px}\n.up-verse-arth{font-size:13px;color:var(--soft);line-height:1.8}\n.up-verse-src{font-size:11px;color:var(--muted);margin-top:6px;font-style:italic}\n.concept-tag{display:inline-block;font-size:11px;padding:3px 10px;border-radius:12px;margin:3px;cursor:pointer;transition:all .15s;border:1px solid transparent}\n.concept-tag:hover{transform:scale(1.05)}\n\n/* ── NOTES ── */\n.notes-wrap{margin-top:1rem}\n.notes-textarea{\n  width:100%;min-height:80px;padding:10px 12px;\n  border:1.5px solid var(--bds);border-radius:var(--rs);\n  font-size:13px;font-family:inherit;resize:vertical;outline:none;\n  background:var(--cream);transition:border-color .2s;line-height:1.7;\n}\n.notes-textarea:focus{border-color:var(--g);background:var(--w)}\n.notes-actions{display:flex;justify-content:space-between;align-items:center;margin-top:6px}\n.notes-save{\n  padding:6px 16px;background:var(--s);color:#fff;\n  border:none;border-radius:20px;font-size:12px;cursor:pointer;font-family:inherit;\n  transition:opacity .15s;font-weight:600;\n}\n.notes-save:hover{opacity:.88}\n.notes-saved{font-size:11px;color:var(--g);opacity:0;transition:opacity .3s}\n.notes-saved.show{opacity:1}\n\n/* ── PROGRESS TRACKER ── */\n.progress-tracker{\n  background:var(--w);border:1px solid var(--bd);border-radius:var(--r);\n  padding:1.2rem;margin-bottom:1rem;box-shadow:var(--shadow);\n}\n.pt-title{font-size:14px;font-weight:700;margin-bottom:12px;display:flex;align-items:center;gap:8px}\n.pt-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-bottom:12px}\n.pt-item{text-align:center;padding:10px 6px;background:var(--cream);border-radius:var(--rs);border:1px solid var(--bd);cursor:pointer;transition:all .15s}\n.pt-item:hover{background:var(--gl)}\n.pt-item.done{background:var(--gl);border-color:var(--g)}\n.pt-icon{font-size:20px;margin-bottom:4px}\n.pt-name{font-size:10px;font-weight:600;color:var(--ink)}\n.pt-status{font-size:9px;color:var(--muted);margin-top:2px}\n.pt-bar-wrap{height:6px;background:var(--bd);border-radius:3px;overflow:hidden;margin-bottom:8px}\n.pt-bar{height:100%;background:linear-gradient(90deg,var(--s),var(--g));border-radius:3px;transition:width .5s ease}\n.pt-percent{font-size:11px;color:var(--muted);text-align:center}\n\n/* ── HYMN ── */\n.hymn-box{border:1.5px solid var(--bds);border-radius:var(--rs);padding:1.2rem;position:relative}\n.hymn-sanskrit{font-family:\'Tiro Devanagari Sanskrit\',serif;font-size:16px;color:var(--ink);line-height:2.1;margin-bottom:10px}\n.hymn-divider{height:1px;background:var(--bds);margin-bottom:10px}\n.hymn-arth{font-size:13px;color:var(--soft);line-height:1.85}\n.hymn-src{font-size:11px;color:var(--muted);margin-top:8px;font-style:italic}\n.hymn-share{position:absolute;top:10px;right:10px;background:none;border:1px solid var(--bds);border-radius:8px;padding:4px 8px;cursor:pointer;font-size:12px;color:var(--muted);transition:all .15s}\n.hymn-share:hover{background:var(--gl);color:var(--g)}\n\n/* ── CONCEPTS ── */\n.concept-chips{display:flex;flex-wrap:wrap;gap:7px;margin-bottom:1rem}\n.chip{\n  font-size:12px;padding:6px 13px;border-radius:20px;\n  background:var(--cream);border:1.5px solid var(--bds);\n  color:var(--soft);cursor:pointer;transition:all .2s;font-family:inherit;\n}\n.chip:hover{transform:translateY(-1px);box-shadow:var(--shadow)}\n.chip.active{font-weight:600;transform:translateY(-1px)}\n\n/* ── QUIZ ── */\n.quiz-wrap{max-width:640px;margin:0 auto}\n.quiz-card{background:var(--w);border:1px solid var(--bd);border-radius:var(--r);padding:1.6rem;box-shadow:var(--shadow-lg);animation:fadeUp .3s ease}\n.qz-top{display:flex;justify-content:space-between;align-items:center;margin-bottom:12px}\n.qz-q-num{font-size:12px;color:var(--muted);font-weight:500}\n.qz-score-badge{background:var(--sl);color:var(--s);border-radius:20px;padding:3px 12px;font-size:12px;font-weight:700}\n.qz-bar{height:5px;background:var(--bd);border-radius:3px;margin-bottom:18px;overflow:hidden}\n.qz-bar-fill{height:100%;background:linear-gradient(90deg,var(--s),var(--g));border-radius:3px;transition:width .4s ease}\n.qz-shloka{font-family:\'Tiro Devanagari Sanskrit\',serif;font-size:14px;color:var(--soft);background:var(--cream);padding:10px 14px;border-radius:var(--rs);margin-bottom:14px;line-height:1.9;border-left:3px solid var(--bds)}\n.qz-q{font-size:15px;font-weight:700;line-height:1.65;margin-bottom:16px;color:var(--ink)}\n.qz-opts{display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:14px}\n.qz-opt{\n  padding:12px 14px;border:1.5px solid var(--bds);border-radius:var(--rs);\n  cursor:pointer;font-size:13px;font-family:inherit;background:var(--w);\n  text-align:left;transition:all .2s;line-height:1.5;font-weight:500;\n}\n.qz-opt:hover:not(:disabled){background:var(--gl);border-color:var(--g);transform:translateY(-1px)}\n.qz-opt.correct{background:#E8F5E9;border-color:#4CAF50;color:#1B5E20;animation:pop .25s ease}\n.qz-opt.wrong{background:#FFEBEE;border-color:#EF5350;color:#B71C1C}\n.qz-opt:disabled{cursor:default}\n.qz-fb{font-size:13px;padding:12px 14px;border-radius:var(--rs);margin-bottom:14px;line-height:1.75;animation:fadeUp .2s ease}\n.qz-fb.correct{background:#E8F5E9;color:#1B5E20;border:1px solid #4CAF50}\n.qz-fb.wrong{background:#FFEBEE;color:#B71C1C;border:1px solid #EF5350}\n.qz-next{width:100%;padding:12px;border:none;border-radius:var(--rs);background:linear-gradient(135deg,var(--s),#C8520A);color:#fff;font-size:14px;font-weight:700;cursor:pointer;font-family:inherit;transition:all .2s;box-shadow:0 4px 12px rgba(232,98,26,.3)}\n.qz-next:hover{transform:translateY(-1px);box-shadow:0 6px 16px rgba(232,98,26,.4)}\n.qz-result{text-align:center;padding:24px 16px}\n.qz-result-num{font-size:52px;font-weight:800;font-family:\'Inter\',sans-serif;background:linear-gradient(135deg,var(--s),var(--g));-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text}\n.qz-result-msg{font-size:15px;color:var(--soft);margin:8px 0 20px;line-height:1.6}\n.qz-restart{padding:12px 32px;border:2px solid var(--s);background:var(--sl);color:var(--s);border-radius:var(--rs);font-size:14px;font-weight:700;cursor:pointer;font-family:inherit;transition:all .2s}\n.qz-restart:hover{background:var(--s);color:#fff}\n\n/* ── RISHIS ── */\n.rishi-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:10px}\n.rishi-card{background:var(--cream);border:1.5px solid var(--bd);border-radius:var(--r);padding:14px;text-align:center;cursor:pointer;transition:all .22s;box-shadow:var(--shadow)}\n.rishi-card:hover{transform:translateY(-3px);box-shadow:var(--shadow-lg)}\n.rishi-card.active{border-width:2px;background:var(--gl)}\n.rishi-icon{font-size:30px;margin-bottom:7px}\n.rishi-name{font-size:13px;font-weight:700}\n.rishi-veda{font-size:10px;color:var(--muted);margin-top:3px}\n.rishi-detail{margin-top:14px;background:var(--cream);border-left:3px solid var(--s);border-radius:0 var(--rs) var(--rs) 0;padding:14px 16px;animation:fadeUp .25s ease}\n.rishi-detail h4{font-size:14px;font-weight:700;margin-bottom:8px}\n.rishi-detail p{font-size:13px;color:var(--soft);line-height:1.9}\n\n/* ── DEITIES ── */\n.deity-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:10px}\n.deity-card{background:var(--cream);border:1.5px solid var(--bd);border-radius:var(--r);padding:14px 10px;text-align:center;cursor:pointer;transition:all .22s;box-shadow:var(--shadow)}\n.deity-card:hover{transform:translateY(-3px);box-shadow:var(--shadow-lg)}\n.deity-card.active{border-width:2px;background:var(--gl)}\n.deity-svg{width:54px;height:54px;margin:0 auto 8px}\n.deity-name{font-size:13px;font-weight:700}\n.deity-role{font-size:10px;color:var(--muted);margin-top:2px}\n.deity-detail{margin-top:14px;background:var(--cream);border-left:3px solid;border-radius:0 var(--rs) var(--rs) 0;padding:14px 16px;animation:fadeUp .25s ease}\n.deity-detail h4{font-size:14px;font-weight:700;margin-bottom:8px}\n.deity-detail p{font-size:13px;color:var(--soft);line-height:1.9}\n\n/* ── TIMELINE ── */\n.timeline{position:relative;padding-left:26px}\n.timeline::before{content:\'\';position:absolute;left:9px;top:0;bottom:0;width:2px;background:linear-gradient(to bottom,var(--s),var(--g))}\n.tl-item{position:relative;margin-bottom:22px;animation:fadeUp .3s ease}\n.tl-dot{position:absolute;left:-21px;top:4px;width:14px;height:14px;border-radius:50%;border:2.5px solid var(--w);box-shadow:var(--shadow)}\n.tl-year{font-size:11px;font-weight:700;font-family:\'Inter\',sans-serif;margin-bottom:4px}\n.tl-title{font-size:14px;font-weight:700;margin-bottom:4px}\n.tl-desc{font-size:13px;color:var(--soft);line-height:1.75}\n\n/* ── DOTS ── */\n.nav-row2{display:flex;justify-content:space-between;align-items:center;margin-bottom:10px}\n.dots{display:flex;gap:7px}\n.dot{width:8px;height:8px;border-radius:50%;background:var(--bds);cursor:pointer;transition:all .2s}\n.dot.active{background:var(--s);transform:scale(1.3)}\n\n/* ── ASK BTN ── */\n.ask-btn{\n  width:100%;padding:13px;border:1.5px solid;border-radius:var(--rs);\n  font-size:13px;font-weight:700;cursor:pointer;font-family:inherit;\n  transition:all .2s;margin-top:4px;\n}\n.ask-btn:hover{transform:translateY(-1px);box-shadow:var(--shadow)}\n\n/* ── MAHAVAKYA WALL ── */\n.mv-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:12px;margin-bottom:1.2rem}\n.mv-card{\n  background:linear-gradient(135deg,#1C0A02,#3D1A05);\n  border-radius:var(--r);padding:1.2rem;cursor:pointer;\n  transition:all .22s;border:1px solid rgba(200,144,10,.3);\n  box-shadow:var(--shadow);\n}\n.mv-card:hover{transform:translateY(-3px);box-shadow:var(--shadow-lg)}\n.mv-sanskrit{font-family:\'Tiro Devanagari Sanskrit\',serif;font-size:17px;color:#FFD700;margin-bottom:8px;line-height:1.6}\n.mv-trans{font-size:12px;color:rgba(255,255,255,.75);margin-bottom:6px;line-height:1.6}\n.mv-source{font-size:10px;color:rgba(255,215,0,.5);font-style:italic}\n\n/* ── TOAST ── */\n.toast{\n  position:fixed;bottom:24px;left:50%;transform:translateX(-50%) translateY(80px);\n  background:#1C0A02;color:#FFD700;padding:10px 20px;border-radius:20px;\n  font-size:13px;font-weight:600;z-index:999;transition:transform .3s ease;\n  border:1px solid rgba(200,144,10,.4);box-shadow:var(--shadow-lg);\n}\n.toast.show{transform:translateX(-50%) translateY(0)}\n\n/* ── FLOATING OM ── */\n.float-om{\n  position:fixed;top:50%;left:50%;transform:translate(-50%,-50%);\n  font-family:\'Tiro Devanagari Sanskrit\',serif;font-size:300px;\n  color:rgba(200,144,10,.025);pointer-events:none;z-index:0;user-select:none;\n  animation:spin 120s linear infinite;\n}\n\n@media(max-width:600px){\n  .veda-tabs{grid-template-columns:repeat(2,1fr)}\n  .section-grid,.up-grid,.mv-grid{grid-template-columns:1fr}\n  .deity-grid,.rishi-grid{grid-template-columns:repeat(2,1fr)}\n  .qz-opts{grid-template-columns:1fr}\n  .up-lesson-grid{grid-template-columns:1fr}\n  .pt-grid,.facts-row{grid-template-columns:repeat(2,1fr)}\n  .container{padding:1rem}\n  .header{padding:.75rem 1rem}\n  .header-tools{gap:4px}\n  .tool-btn{padding:4px 9px;font-size:11px}\n  .float-om{font-size:160px}\n}\n</style>\n</head>\n<body>\n\n<div class="float-om">ॐ</div>\n\n<header class="header">\n  <div class="header-om">ॐ</div>\n  <div class="header-text">\n    <h1 id="hTitle">वेद ज्ञान</h1>\n    <p id="hSub">चारों वेदों की आसान जानकारी</p>\n  </div>\n  <div class="header-tools">\n    <button class="tool-btn" onclick="toggleLang()" id="langBtn">🌐 English</button>\n    <button class="tool-btn" onclick="changeFontSize(-1)" style="font-size:13px">A−</button>\n    <button class="tool-btn" onclick="changeFontSize(1)" style="font-size:14px">A+</button>\n    <button class="tool-btn" onclick="showPage(\'bookmarks\')" id="bmBtn">🔖 <span id="bmCount">0</span></button>\n  </div>\n</header>\n\n<nav class="main-nav" id="mainNav">\n  <button class="nav-tab active" onclick="showPage(\'home\')" id="n0">📚 <span id="nl0">वेद</span></button>\n  <button class="nav-tab" onclick="showPage(\'upanishads\')" id="n1">🧘 <span id="nl1">उपनिषद</span></button>\n  <button class="nav-tab" onclick="showPage(\'mahavakya\')" id="n2">✨ <span id="nl2">महावाक्य</span></button>\n  <button class="nav-tab" onclick="showPage(\'rishis\')" id="n3">🙏 <span id="nl3">ऋषि</span></button>\n  <button class="nav-tab" onclick="showPage(\'deities\')" id="n4">⚡ <span id="nl4">देवता</span></button>\n  <button class="nav-tab" onclick="showPage(\'timeline\')" id="n5">📅 <span id="nl5">काल</span></button>\n  <button class="nav-tab" onclick="showPage(\'quiz\')" id="n6">🎯 <span id="nl6">प्रश्नोत्तरी</span></button>\n  <button class="nav-tab" onclick="showPage(\'progress\')" id="n7">📈 <span id="nl7">प्रगति</span></button>\n</nav>\n\n<div id="toast" class="toast"></div>\n<div class="container" id="app"></div>\n\n<script>\n/* ────────── STATE ────────── */\nlet lang=\'hi\', fontSize=14, currentPage=\'home\';\nlet activeVeda=0, activeSection=0, activeConcept=null, activeUpanishad=null;\nlet activeUpFilter=\'all\', activeUpTab=\'story\';\nlet activeDeity=null, activeRishi=null;\nlet quizState={idx:0,score:0,answered:false,sel:null,done:false};\nlet notes=JSON.parse(localStorage.getItem(\'vg_notes\')||\'{}\');\nlet bookmarks=JSON.parse(localStorage.getItem(\'vg_bm\')||\'[]\');\nlet readProgress=JSON.parse(localStorage.getItem(\'vg_prog\')||\'{}\');\n\n/* ────────── HELPERS ────────── */\nconst $=id=>document.getElementById(id);\nconst L=o=>typeof o===\'object\'?(o[lang]||o.hi):o;\nfunction save(k,v){localStorage.setItem(k,JSON.stringify(v))}\nfunction toast(msg){const t=$(\'toast\');t.textContent=msg;t.classList.add(\'show\');setTimeout(()=>t.classList.remove(\'show\'),2200)}\n\nfunction toggleLang(){\n  lang=lang===\'hi\'?\'en\':\'hi\';\n  $(\'langBtn\').textContent=lang===\'hi\'?\'🌐 English\':\'🌐 हिंदी\';\n  document.body.classList.toggle(\'en\',lang===\'en\');\n  $(\'hTitle\').textContent=lang===\'hi\'?\'वेद ज्ञान\':\'Veda Gyan\';\n  $(\'hSub\').textContent=lang===\'hi\'?\'चारों वेदों की आसान जानकारी\':\'Easy guide to the four Vedas\';\n  const nl=lang===\'hi\'?[\'वेद\',\'उपनिषद\',\'महावाक्य\',\'ऋषि\',\'देवता\',\'काल\',\'प्रश्नोत्तरी\',\'प्रगति\']:\n                       [\'Vedas\',\'Upanishads\',\'Mahavakyas\',\'Rishis\',\'Deities\',\'Timeline\',\'Quiz\',\'Progress\'];\n  nl.forEach((l,i)=>{$(\'nl\'+i).textContent=l});\n  showPage(currentPage,true);\n}\nfunction changeFontSize(d){\n  fontSize=Math.max(12,Math.min(19,fontSize+d));\n  document.documentElement.style.setProperty(\'--fs\',fontSize+\'px\');\n}\nfunction markRead(id){\n  readProgress[id]=true; save(\'vg_prog\',readProgress);\n  $(\'bmCount\').textContent=bookmarks.length;\n  toast(lang===\'hi\'?\'✅ पढ़ा हुआ माना गया!\':\'✅ Marked as read!\');\n  if($(\'app\')) showPage(currentPage,true);\n}\nfunction toggleBM(id){\n  const i=bookmarks.indexOf(id);\n  if(i>-1)bookmarks.splice(i,1); else bookmarks.push(id);\n  save(\'vg_bm\',bookmarks);\n  $(\'bmCount\').textContent=bookmarks.length;\n  toast(i>-1?(lang===\'hi\'?\'🔖 बुकमार्क हटाया\':\'🔖 Bookmark removed\'):(lang===\'hi\'?\'🔖 बुकमार्क किया!\':\'🔖 Bookmarked!\'));\n  showPage(currentPage,true);\n}\nfunction saveNote(key){\n  const v=$(\'note_\'+key);if(!v)return;\n  notes[key]=v.value; save(\'vg_notes\',notes);\n  const s=$(\'note_saved_\'+key);if(s){s.classList.add(\'show\');setTimeout(()=>s.classList.remove(\'show\'),1500)}\n  toast(lang===\'hi\'?\'📝 नोट सेव हो गया!\':\'📝 Note saved!\');\n}\nfunction shareText(txt){\n  window.open(\'https://wa.me/?text=\'+encodeURIComponent(txt+\'\\n— वेद ज्ञान App\'),\'_blank\');\n}\n\nfunction showPage(p,noScroll){\n  currentPage=p;\n  for(let i=0;i<8;i++){const b=$(\'n\'+i);if(b)b.classList.remove(\'active\')}\n  const map={home:0,upanishads:1,mahavakya:2,rishis:3,deities:4,timeline:5,quiz:6,progress:7,bookmarks:-1};\n  if(map[p]>=0&&$(\'n\'+map[p]))$(\'n\'+map[p]).classList.add(\'active\');\n  const pages={home:renderHome,upanishads:renderUpanishads,mahavakya:renderMahavakya,\n               rishis:renderRishis,deities:renderDeities,timeline:renderTimeline,\n               quiz:renderQuiz,progress:renderProgress,bookmarks:renderBookmarks};\n  if(pages[p])pages[p]();\n  if(!noScroll)window.scrollTo(0,0);\n}\n\n/* ────────── DATA ────────── */\nconst DAILY=[\n  {s:\'तमसो मा ज्योतिर्गमय।\\nमृत्योर्मा अमृतं गमय।\',m:{hi:\'अंधेरे से रोशनी की तरफ ले जाओ। मृत्यु से अमरता की तरफ।\',en:\'Lead me from darkness to light. From death to immortality.\'},src:\'बृहदारण्यक उपनिषद 1.3.28\'},\n  {s:\'सर्वे भवन्तु सुखिनः।\\nसर्वे सन्तु निरामयाः।\',m:{hi:\'सभी सुखी हों। सभी रोग-मुक्त हों।\',en:\'May all be happy. May all be free from illness.\'},src:\'बृहदारण्यक उपनिषद\'},\n  {s:\'अहम् ब्रह्मास्मि।\',m:{hi:\'"मैं ही ब्रह्म हूं" — तुम्हारी आत्मा और परमात्मा एक हैं।\',en:\'"I am Brahman" — your self and the ultimate reality are one.\'},src:\'बृहदारण्यक उपनिषद 1.4.10\'},\n  {s:\'तत् त्वम् असि।\',m:{hi:\'"वह तुम हो" — परमात्मा और तुम्हारी आत्मा अलग नहीं।\',en:\'"That thou art" — God and your soul are not separate.\'},src:\'छांदोग्य उपनिषद 6.8.7\'},\n  {s:\'ईशावास्यमिदम् सर्वम्।\',m:{hi:\'"यह पूरी दुनिया परमात्मा से भरी है।"\',en:\'"All this universe is pervaded by God."\'},src:\'ईशावास्योपनिषद 1\'},\n  {s:\'माता भूमिः पुत्रोऽहं पृथिव्याः।\',m:{hi:\'धरती मेरी माँ है, मैं उसका बेटा हूं।\',en:\'Earth is my mother, I am her son.\'},src:\'अथर्ववेद 12.1.12\'},\n  {s:\'योगः कर्मसु कौशलम्।\',m:{hi:\'योग यानी हर काम को कुशलता से करना।\',en:\'Yoga is excellence/skill in action.\'},src:\'भगवद्गीता 2.50\'},\n];\n\nconst VEDAS=[\n  {id:\'rig\',name:{hi:\'ऋग्वेद\',en:\'Rigveda\'},sub:{hi:\'स्तुतियों का वेद\',en:\'Veda of Hymns\'},icon:\'🔥\',\n   c:\'#BA7517\',bg:\'#FDF6E3\',bd:\'#C8900A\',\n   p:{hi:\'यह सबसे पुराना वेद है (करीब 1500 ईसा पूर्व)। इसमें देवताओं की प्रशंसा में लिखे गए 1,028 भजन हैं। यह सारे वैदिक साहित्य की नींव है।\',en:\'The oldest Veda (~1500 BCE), containing 1,028 hymns praising the gods of nature. Foundation of all Vedic literature.\'},\n   facts:[{n:\'1,028\',l:{hi:\'सूक्त (भजन)\',en:\'Hymns\'}},{n:\'10,552\',l:{hi:\'ऋचाएं (श्लोक)\',en:\'Verses\'}},{n:\'10\',l:{hi:\'मंडल (भाग)\',en:\'Mandalas\'}}],\n   badges:{hi:[\'सबसे पुराना\',\'1,028 भजन\',\'10 मंडल\'],en:[\'Oldest Veda\',\'1,028 Hymns\',\'10 Books\']},\n   secs:[{n:{hi:\'मंडल\',en:\'Mandalas\'},s:{hi:\'10 मुख्य भाग\',en:\'10 books\'},i:\'📖\'},\n         {n:{hi:\'संहिता\',en:\'Samhita\'},s:{hi:\'मूल मंत्र\',en:\'Core hymns\'},i:\'📜\'},\n         {n:{hi:\'ब्राह्मण\',en:\'Brahmanas\'},s:{hi:\'पूजा विधि\',en:\'Ritual texts\'},i:\'🕯\'},\n         {n:{hi:\'उपनिषद\',en:\'Upanishads\'},s:{hi:\'दर्शन\',en:\'Philosophy\'},i:\'🧘\'}],\n   secD:[\n     {t:{hi:\'मंडल — 10 मुख्य भाग\',en:\'Mandalas — 10 Books\'},d:{hi:\'ऋग्वेद 10 मंडलों में बंटा है। मंडल 2–7 सबसे पुराने हैं — ये अलग ऋषि परिवारों ने लिखे। मंडल 1, 8, 9, 10 बाद में जोड़े गए। हर मंडल में कई सूक्त (भजन समूह) हैं।\',en:\'The Rigveda is organized into 10 Mandalas. Books 2–7 are oldest "family books" by sage lineages. Books 1, 8, 9, 10 added later. Each book contains many suktas (hymns).\'}},\n     {t:{hi:\'संहिता — मूल मंत्र\',en:\'Samhita — Core Hymns\'},d:{hi:\'संहिता माने वेद का वो हिस्सा जिसमें सभी मंत्र इकट्ठे हैं। 10,552 श्लोक हैं। ज़्यादातर मंत्र अग्नि देव और इंद्र देव की प्रशंसा में।\',en:\'The Samhita is the core collection of mantras — 10,552 verses mostly praising Agni and Indra.\'}},\n     {t:{hi:\'ब्राह्मण — पूजा विधि\',en:\'Brahmanas — Ritual Guides\'},d:{hi:\'ये किताबें बताती हैं कि यज्ञ कैसे करना है। ऋग्वेद का ब्राह्मण "ऐतरेय ब्राह्मण" है। इसमें सोम यज्ञ और राजाभिषेक की विधि है।\',en:\'Texts explaining how to perform yajnas (sacrifices). The Rigveda\\\'s Brahmana is the Aitareya Brahmana, covering soma rituals and royal consecrations.\'}},\n     {t:{hi:\'उपनिषद — ऐतरेय और कौषीतकि\',en:\'Upanishads — Aitareya & Kaushitaki\'},d:{hi:\'ऐतरेय उपनिषद — सृष्टि कैसे बनी, "प्रज्ञानम् ब्रह्म।" कौषीतकि उपनिषद — प्राण और ब्रह्मन। उपनिषद पेज पर और जानें।\',en:\'Aitareya — how creation happened, "Consciousness is Brahman." Kaushitaki — on Prana and Brahman. See the Upanishads page for details.\'}}\n   ],\n   hymn:{s:\'अग्निमीळे पुरोहितं यज्ञस्य देवमृत्विजम्।\\nहोतारं रत्नधातमम्॥\',a:{hi:\'"मैं अग्नि देव की प्रशंसा करता हूं — यज्ञ के पुजारी, देवताओं में श्रेष्ठ, और सभी अच्छी चीजें देने वाले।"\',en:\'"I praise Agni, the divine priest of the sacrifice, the ministrant, the invoker, the best bestower of treasures."\'},src:\'ऋग्वेद / Rigveda 1.1.1\'},\n   concepts:{hi:[\'अग्नि देव\',\'इंद्र देव\',\'सोम\',\'वरुण देव\',\'ऋत (सच्चाई)\',\'गायत्री मंत्र\'],en:[\'Agni (Fire)\',\'Indra (Storm)\',\'Soma\',\'Varuna\',\'Rita (Order)\',\'Gayatri Mantra\']},\n   ci:{\'अग्नि देव\':{hi:\'अग्नि देव मनुष्यों और देवताओं के बीच दूत हैं। यज्ञ में डाली आहुति को देवताओं तक पहुंचाते हैं।\',en:\'Agni is the divine messenger carrying offerings to the gods through the sacred fire.\'},\n       \'इंद्र देव\':{hi:\'देवताओं के राजा — बिजली, बारिश और युद्ध के देव। उन्होंने अजगर वृत्र को मारकर पानी आज़ाद किया।\',en:\'King of the gods — deity of lightning, rain and war. Slew the serpent Vritra to release cosmic waters.\'},\n       \'सोम\':{hi:\'एक पवित्र पेय और देव। ताज़गी, खुशी और अमरता का प्रतीक। यज्ञ में चढ़ाया जाता था।\',en:\'A sacred ritual drink and deity. Symbol of immortality, inspiration and divine joy. Offered in yajna.\'},\n       \'वरुण देव\':{hi:\'सत्य और न्याय के देव। सब कुछ देखते हैं। सच्चे मन से माफी मांगने वाले को माफ करते हैं।\',en:\'God of truth and justice. Sees all deeds. Forgives those who sincerely repent.\'},\n       \'ऋत (सच्चाई)\':{hi:\'ब्रह्मांड का सच्चा नियम — जैसे सूरज हर रोज उगता है। यही बाद में "धर्म" बना।\',en:\'The cosmic law of truth — the natural order. It later evolved into the concept of Dharma.\'},\n       \'गायत्री मंत्र\':{hi:\'"ॐ भूर्भुवः स्वः..." — सूर्य देव को लिखा सबसे पवित्र वैदिक मंत्र। अर्थ: "हे सूर्य, हमारी बुद्धि को सही रास्ता दिखाओ।"\',en:\'"Om Bhur Bhuvah Svah..." — The most sacred Vedic mantra to the Sun. Meaning: "O Sun, illuminate our intellect on the right path."\'}}\n  },\n  {id:\'sama\',name:{hi:\'सामवेद\',en:\'Samaveda\'},sub:{hi:\'गानों का वेद\',en:\'Veda of Melodies\'},icon:\'🎵\',\n   c:\'#185FA5\',bg:\'#E8F2FC\',bd:\'#378ADD\',\n   p:{hi:\'यह गानों का वेद है। इसके मंत्र सोम यज्ञ के दौरान गाए जाते थे। भारतीय शास्त्रीय संगीत की शुरुआत यहीं से हुई।\',en:\'The Veda of Songs. Verses were sung during the Soma sacrifice. Indian classical music traces its origins here.\'},\n   facts:[{n:\'1,875\',l:{hi:\'ऋचाएं\',en:\'Verses\'}},{n:\'75\',l:{hi:\'मंत्र — खुद के\',en:\'Original mantras\'}},{n:\'3\',l:{hi:\'ग्रंथ शाखाएं\',en:\'Textual branches\'}}],\n   badges:{hi:[\'संगीत का वेद\',\'1,875 ऋचाएं\',\'भारतीय संगीत का जन्म\'],en:[\'Veda of Music\',\'1,875 Verses\',\'Root of Indian Music\']},\n   secs:[{n:{hi:\'पूर्वार्चिक\',en:\'Purvarchika\'},s:{hi:\'पहला भाग\',en:\'First section\'},i:\'🎶\'},\n         {n:{hi:\'उत्तरार्चिक\',en:\'Uttararchika\'},s:{hi:\'दूसरा भाग\',en:\'Second section\'},i:\'🎼\'},\n         {n:{hi:\'ब्राह्मण\',en:\'Brahmanas\'},s:{hi:\'यज्ञ जानकारी\',en:\'Ritual texts\'},i:\'📋\'},\n         {n:{hi:\'उपनिषद\',en:\'Upanishads\'},s:{hi:\'छांदोग्य व केन\',en:\'Chandogya & Kena\'},i:\'🧘\'}],\n   secD:[\n     {t:{hi:\'पूर्वार्चिक — पहला भाग\',en:\'Purvarchika — First Section\'},d:{hi:\'585 ऋचाएं, ज़्यादातर ऋग्वेद से ली गई लेकिन राग में सजाई गई। 6 अध्यायों में बंटी।\',en:\'585 verses, mostly from the Rigveda but arranged for melodic singing. Organized in 6 chapters.\'}},\n     {t:{hi:\'उत्तरार्चिक — दूसरा भाग\',en:\'Uttararchika — Second Section\'},d:{hi:\'1,225 ऋचाएं। सोम यज्ञ के दौरान गाई जाती थीं। हर यज्ञ के हिस्से में अलग राग।\',en:\'1,225 verses sung during the Soma sacrifice. Different melodies prescribed for each stage of the ritual.\'}},\n     {t:{hi:\'ब्राह्मण — यज्ञ की जानकारी\',en:\'Brahmanas — Ritual Guides\'},d:{hi:\'तांड्य महाब्राह्मण और जैमिनीय ब्राह्मण — सोम यज्ञ में कब कौन सा गाना गाना है।\',en:\'Tandya Mahabrahmana and Jaiminiya Brahmana specify which melodies to sing at each stage of the Soma sacrifice.\'}},\n     {t:{hi:\'उपनिषद — छांदोग्य और केन\',en:\'Upanishads — Chandogya & Kena\'},d:{hi:\'छांदोग्य — "तत् त्वम् असि" (वह तुम हो)। केन — "किसके कारण मन सोचता है?" उपनिषद पेज पर और जानें।\',en:\'Chandogya — "Tat tvam asi" (That thou art). Kena — "By whose will does the mind think?" See Upanishads page.\'}}\n   ],\n   hymn:{s:\'ॐ इत्येतदक्षरमुद्गीथमुपासीत।\\nओमिति ह्युद्गायति।\',a:{hi:\'"ॐ — इस अक्षर को उद्गीथ (मुख्य गान) मानकर पूजो। उद्गातृ पुजारी ॐ से ही गाना शुरू करता है।"\',en:\'"Meditate upon Om as the Udgitha. The Udgatr priest begins singing with Om."\'},src:\'छांदोग्य उपनिषद 1.1.1\'},\n   concepts:{hi:[\'सामन (राग)\',\'उद्गीथ\',\'तत् त्वम् असि\',\'सोम यज्ञ\',\'सात स्वर\',\'छांदोग्य\'],en:[\'Saman (Melody)\',\'Udgitha\',\'Tat Tvam Asi\',\'Soma Yajna\',\'Seven Notes\',\'Chandogya\']},\n   ci:{\'सामन (राग)\':{hi:\'सामवेद के मंत्रों को राग में गाया जाता था। पाँच स्वरों में। यही भारतीय शास्त्रीय संगीत की शुरुआत है।\',en:\'The melodic chants of the Samaveda, sung in a pentatonic scale — the ancestor of Indian classical music.\'},\n       \'उद्गीथ\':{hi:\'सोम यज्ञ का सबसे ज़रूरी गाना — ॐ से शुरू होता है। यही ब्रह्मन का प्रतीक है।\',en:\'The central chant of the Soma sacrifice, beginning with Om — symbol of Brahman.\'},\n       \'तत् त्वम् असि\':{hi:\'"वह तुम हो" — तुम्हारी आत्मा और परमात्मा एक हैं। वेदांत का सबसे बड़ा सन्देश।\',en:\'"That thou art" — your individual self and Brahman are one. The greatest message of Vedanta.\'},\n       \'सोम यज्ञ\':{hi:\'मुख्य वैदिक यज्ञ जिसमें सोम रस चढ़ाया जाता था। सामवेद के सारे गाने इसी के लिए थे।\',en:\'The central Vedic sacrifice involving Soma juice. All Samaveda songs were composed for this ritual.\'},\n       \'सात स्वर\':{hi:\'सा, रे, ग, म, प, ध, नि — ये सात स्वर सामवेद की गायन परंपरा से आए।\',en:\'Sa Re Ga Ma Pa Dha Ni — the seven musical notes derived from the Samaveda singing tradition.\'},\n       \'छांदोग्य\':{hi:\'सबसे बड़े उपनिषदों में से एक। "तत् त्वम् असि" और नमक-पानी का प्रसिद्ध उदाहरण।\',en:\'One of the largest Upanishads. Famous "Tat tvam asi" teaching and the salt-in-water example.\'}}\n  },\n  {id:\'yajur\',name:{hi:\'यजुर्वेद\',en:\'Yajurveda\'},sub:{hi:\'यज्ञों का वेद\',en:\'Veda of Rituals\'},icon:\'🕯\',\n   c:\'#3B6D11\',bg:\'#EAF3DE\',bd:\'#639922\',\n   p:{hi:\'यज्ञ की विधि बताने वाला वेद। इसमें वो मंत्र हैं जो यज्ञ करते समय बोले जाते थे। इसमें रुद्र (शिव) और विष्णु की स्तुति भी है।\',en:\'The Veda of ritual formulas. Contains prose mantras recited during sacrifices, plus famous hymns to Rudra and Vishnu.\'},\n   facts:[{n:\'1,975+\',l:{hi:\'मंत्र\',en:\'Mantras\'}},{n:\'2\',l:{hi:\'मुख्य शाखाएं\',en:\'Main branches\'}},{n:\'40\',l:{hi:\'अध्याय (शुक्ल)\',en:\'Chapters (Shukla)\'}}],\n   badges:{hi:[\'यज्ञ का वेद\',\'2 शाखाएं\',\'श्री रुद्रम् का स्रोत\'],en:[\'Veda of Ritual\',\'2 Branches\',\'Source of Sri Rudram\']},\n   secs:[{n:{hi:\'कृष्ण यजुर्वेद\',en:\'Krishna Yajurveda\'},s:{hi:\'मिला-जुला रूप\',en:\'Mixed form\'},i:\'⚫\'},\n         {n:{hi:\'शुक्ल यजुर्वेद\',en:\'Shukla Yajurveda\'},s:{hi:\'साफ मंत्र\',en:\'Pure mantras\'},i:\'⚪\'},\n         {n:{hi:\'शतपथ ब्राह्मण\',en:\'Shatapatha Brahmana\'},s:{hi:\'बड़ी किताब\',en:\'100 chapters\'},i:\'📚\'},\n         {n:{hi:\'उपनिषद\',en:\'Upanishads\'},s:{hi:\'बृहदारण्यक व ईश\',en:\'Brihadaranyaka & Isha\'},i:\'🧘\'}],\n   secD:[\n     {t:{hi:\'कृष्ण यजुर्वेद\',en:\'Krishna Yajurveda\'},d:{hi:\'"कृष्ण" इसलिए कि मंत्र और व्याख्या साथ-साथ। मुख्य शाखाएं: तैत्तिरीय और मैत्रायणी। श्री रुद्रम् यहाँ है।\',en:\'"Krishna" (dark) — mantras and commentary mixed together. Main branches: Taittiriya and Maitrayani. Source of Sri Rudram.\'}},\n     {t:{hi:\'शुक्ल यजुर्वेद\',en:\'Shukla Yajurveda\'},d:{hi:\'"शुक्ल" इसलिए कि मंत्र और व्याख्या अलग-अलग। दो शाखाएं: वाजसनेयी और काण्व। ईशावास्योपनिषद यहाँ है।\',en:\'"Shukla" (pure) — mantras and commentary in separate texts. Branches: Vajasaneyi and Kanva. Source of Isha Upanishad.\'}},\n     {t:{hi:\'शतपथ ब्राह्मण — 100 अध्याय\',en:\'Shatapatha Brahmana — 100 Chapters\'},d:{hi:\'सबसे महत्वपूर्ण ब्राह्मण ग्रंथ। अग्निचयन यज्ञ में 10,800 ईंटों से बाज के आकार की वेदी बनाई जाती थी।\',en:\'Most important Brahmana text. The Agnichayana ritual involved building a falcon-shaped altar with 10,800 bricks.\'}},\n     {t:{hi:\'उपनिषद — बृहदारण्यक और ईशावास्य\',en:\'Upanishads — Brihadaranyaka & Isha\'},d:{hi:\'बृहदारण्यक — सबसे बड़ा उपनिषद, याज्ञवल्क्य। ईशावास्य — 18 श्लोक, गांधीजी का पसंदीदा। उपनिषद पेज पर और जानें।\',en:\'Brihadaranyaka — largest Upanishad, Yajnavalkya\\\'s teachings. Isha — 18 verses, Gandhi\\\'s favorite. See Upanishads page.\'}}\n   ],\n   hymn:{s:\'शं नो मित्रः शं वरुणः।\\nशं नो भवत्वर्यमा।\\nशं न इन्द्रो बृहस्पतिः।\\nशं नो विष्णुरुरुक्रमः॥\',a:{hi:\'"मित्र, वरुण, अर्यमा, इंद्र, बृहस्पति और विष्णु — सभी हमें सुख और शांति दें।"\',en:\'"May Mitra, Varuna, Aryaman, Indra, Brihaspati and Vishnu grant us peace and happiness."\'},src:\'तैत्तिरीयोपनिषद, शांति पाठ\'},\n   concepts:{hi:[\'श्री रुद्रम्\',\'याज्ञवल्क्य\',\'नेति नेति\',\'ईशावास्योपनिषद\',\'अग्निचयन\',\'अध्वर्यु\'],en:[\'Sri Rudram\',\'Yajnavalkya\',\'Neti Neti\',\'Isha Upanishad\',\'Agnichayana\',\'Adhvaryu Priest\']},\n   ci:{\'श्री रुद्रम्\':{hi:\'कृष्ण यजुर्वेद का बहुत प्रसिद्ध भजन — रुद्र (शिव) के 108 नाम। आज भी मंदिरों में गाया जाता है।\',en:\'Famous hymn with 108 names of Rudra (proto-Shiva). Still widely chanted in temples today.\'},\n       \'याज्ञवल्क्य\':{hi:\'बृहदारण्यक उपनिषद के महान ऋषि। उनकी पत्नी मैत्रेयी भी दार्शनिक थीं। "नेति नेति" उनकी शिक्षा।\',en:\'Great sage of Brihadaranyaka. His wife Maitreyi was also a philosopher. Famous for "Neti Neti."\'},\n       \'नेति नेति\':{hi:\'"न यह, न यह" — परमात्मा को किसी शब्द में नहीं बताया जा सकता। हर चीज़ को हटाते जाओ।\',en:\'"Not this, not this" — Brahman transcends all description. Eliminate everything — what remains is Brahman.\'},\n       \'ईशावास्योपनिषद\':{hi:\'सबसे छोटा उपनिषद — 18 श्लोक। "पूरी दुनिया परमात्मा की है।" गांधीजी का पसंदीदा।\',en:\'Shortest Upanishad — 18 verses. "All universe is pervaded by God." Gandhi\\\'s favorite scripture.\'},\n       \'अग्निचयन\':{hi:\'10,800 ईंटों से बाज के आकार की वेदी — वैदिक काल का सबसे मुश्किल यज्ञ।\',en:\'Falcon-shaped altar with 10,800 bricks — the most complex Vedic ritual.\'},\n       \'अध्वर्यु\':{hi:\'यजुर्वेद का पुजारी जो यज्ञ में सारे काम करता है और हर काम के साथ यजुर्वेद के मंत्र बोलता है।\',en:\'The Yajurveda priest who performs all ritual actions and recites Yajus formulas at each step.\'}}\n  },\n  {id:\'atharva\',name:{hi:\'अथर्ववेद\',en:\'Atharvaveda\'},sub:{hi:\'जीवन ज्ञान का वेद\',en:\'Veda of Everyday Life\'},icon:\'🌿\',\n   c:\'#534AB7\',bg:\'#EEEDFE\',bd:\'#7F77DD\',\n   p:{hi:\'यह चौथा और सबसे अलग वेद है। इसमें बीमारी का इलाज, घर की खुशहाली और गहरे सवाल हैं। आयुर्वेद की जड़ें यहीं हैं।\',en:\'The most unique Veda. Contains healing spells, household welfare and deep philosophy. Roots of Ayurveda lie here.\'},\n   facts:[{n:\'730\',l:{hi:\'सूक्त (भजन)\',en:\'Hymns\'}},{n:\'~6,000\',l:{hi:\'श्लोक\',en:\'Verses\'}},{n:\'20\',l:{hi:\'अध्याय\',en:\'Chapters\'}}],\n   badges:{hi:[\'चौथा वेद\',\'730 सूक्त\',\'आयुर्वेद का स्रोत\'],en:[\'4th Veda\',\'730 Hymns\',\'Source of Ayurveda\']},\n   secs:[{n:{hi:\'शौनकीया\',en:\'Shaunakiya\'},s:{hi:\'मुख्य संहिता\',en:\'Main text\'},i:\'📗\'},\n         {n:{hi:\'पैप्पलाद\',en:\'Paippalada\'},s:{hi:\'पुरानी संहिता\',en:\'Older text\'},i:\'📕\'},\n         {n:{hi:\'गोपथ ब्राह्मण\',en:\'Gopatha Brahmana\'},s:{hi:\'एकमात्र ब्राह्मण\',en:\'Only Brahmana\'},i:\'📋\'},\n         {n:{hi:\'उपनिषद\',en:\'Upanishads\'},s:{hi:\'मुंडक व माण्डूक्य\',en:\'Mundaka & Mandukya\'},i:\'🧘\'}],\n   secD:[\n     {t:{hi:\'शौनकीया — मुख्य संहिता\',en:\'Shaunakiya — Main Collection\'},d:{hi:\'20 अध्यायों में 730 सूक्त। बीमारी के मंत्र, प्यार के मंत्र, राजा के अनुष्ठान और 63 श्लोकों का "पृथ्वी सूक्त।"\',en:\'730 hymns in 20 chapters. Healing spells, love charms, royal rituals and the 63-verse "Prithvi Sukta" (Earth Hymn).\'}},\n     {t:{hi:\'पैप्पलाद — पुरानी संहिता\',en:\'Paippalada — Older Recension\'},d:{hi:\'अथर्ववेद का और भी पुराना रूप — कश्मीर की पुरानी किताबों से मिला। 20वीं सदी में दोबारा मिला।\',en:\'An even older version found in Kashmiri manuscripts. Long thought lost, rediscovered in the 20th century.\'}},\n     {t:{hi:\'गोपथ ब्राह्मण\',en:\'Gopatha Brahmana\'},d:{hi:\'अथर्ववेद की एकमात्र ब्राह्मण किताब। बाकी से अलग — ज़्यादा कहानियां। ब्रह्मा को सबसे बड़ा देव बताया।\',en:\'The only Brahmana of the Atharvaveda — more mythological than others. Brahma (the creator) is supreme here.\'}},\n     {t:{hi:\'उपनिषद — मुंडक और माण्डूक्य\',en:\'Upanishads — Mundaka & Mandukya\'},d:{hi:\'मुंडक — दो तरह का ज्ञान। माण्डूक्य — 12 श्लोक, ॐ की 4 अवस्थाएं। उपनिषद पेज पर और जानें।\',en:\'Mundaka — two kinds of knowledge. Mandukya — 12 verses, 4 states of Om. See Upanishads page.\'}}\n   ],\n   hymn:{s:\'माता भूमिः पुत्रोऽहं पृथिव्याः।\\nपर्जन्यः पिता स उ नः पिपर्तु॥\',a:{hi:\'"धरती मेरी माँ है, मैं उसका बेटा हूं। बारिश (पर्जन्य) मेरे पिता हैं — वे हमारा पालन करें।"\',en:\'"Earth is my mother, I am her son. May Parjanya (rain) the father nourish us."\'},src:\'अथर्ववेद 12.1.12 (पृथ्वी सूक्त)\'},\n   concepts:{hi:[\'पृथ्वी सूक्त\',\'आयुर्वेद\',\'माण्डूक्य\',\'ॐ / AUM\',\'ब्रह्मन\',\'काम (इच्छा)\'],en:[\'Prithvi Sukta\',\'Ayurveda\',\'Mandukya\',\'Om / AUM\',\'Brahman\',\'Kama (Desire)\']},\n   ci:{\'पृथ्वी सूक्त\':{hi:\'सभी वेदों का सबसे लंबा भजन — 63 श्लोक। धरती माता की तारीफ। नदियां, पहाड़, पेड़-पौधे। दुनिया का सबसे पुराना पर्यावरण-प्रेम।\',en:\'The longest hymn in all Vedas — 63 verses praising Mother Earth, rivers, mountains, plants. World\\\'s oldest ecology text.\'},\n       \'आयुर्वेद\':{hi:\'अथर्ववेद में बीमारियों के इलाज, जड़ी-बूटियों के मंत्र हैं। यहीं से आयुर्वेद की शुरुआत हुई।\',en:\'Atharvaveda contains herbal remedies and healing spells — the foundation of Ayurveda (traditional Indian medicine).\'},\n       \'माण्डूक्य\':{hi:\'12 श्लोक वाला उपनिषद। ॐ और चेतना की 4 अवस्थाएं। शंकराचार्य: "अकेला काफी है।"\',en:\'12-verse Upanishad. Om and 4 states of consciousness. Shankaracharya: "This alone is sufficient for liberation."\'},\n       \'ॐ / AUM\':{hi:\'सबसे पवित्र ध्वनि। अ = जागना, उ = सपना, म = गहरी नींद, मौन = तुरीय (परमात्मा)।\',en:\'The primordial sound. A = waking, U = dream, M = deep sleep, silence = Turiya (pure consciousness/Brahman).\'},\n       \'ब्रह्मन\':{hi:\'वह शक्ति जो हर जगह है — शुद्ध चेतना। जब हम यह जान लेते हैं — वही मोक्ष है।\',en:\'The ultimate reality pervading everything — pure consciousness. Knowing this is moksha (liberation).\'},\n       \'काम (इच्छा)\':{hi:\'अथर्ववेद में काम-देव के मंत्र हैं। इच्छा को बुरा नहीं माना — यह सृष्टि की ज़रूरी शक्ति है।\',en:\'Atharvaveda contains love hymns invoking Kama. Desire is not condemned here — it is a necessary cosmic creative force.\'}}\n  }\n];\n\nconst UPANISHADS=[\n  {id:\'aitareya\',name:{hi:\'ऐतरेय उपनिषद\',en:\'Aitareya Upanishad\'},\n   veda:{hi:\'ऋग्वेद\',en:\'Rigveda\'},vedaId:\'rig\',vedaColor:\'#BA7517\',\n   chapters:{hi:\'3 अध्याय\',en:\'3 Chapters\'},verses:{hi:\'~33 श्लोक\',en:\'~33 Verses\'},\n   level:{hi:\'शुरुआती\',en:\'Beginner\'},\n   teaser:{hi:\'सृष्टि की उत्पत्ति — शुरू में सिर्फ आत्मा थी।\',en:\'How creation happened — in the beginning only the Self existed.\'},\n   mv:\'प्रज्ञानम् ब्रह्म\',\n   mv_arth:{hi:\'"ज्ञान (चेतना) ही ब्रह्म है"\',en:\'"Consciousness is Brahman"\'},\n   story:{hi:`<strong>मुख्य शिक्षा:</strong> यह बहुत छोटा और सरल उपनिषद है — शुरुआत करने के लिए सबसे अच्छा।\\n\\nइसमें बताया गया है कि शुरू में सिर्फ आत्मा (Self) थी। उसने सोचा — "मैं अकेला हूं, मुझे और बनाना चाहिए।" उसने पहले मन (mind) बनाया, फिर आकाश (space), फिर हवा (air), फिर पानी (water), फिर धरती (earth) बनाई।\\n\\nफिर उसने इंसान बनाया और उसके शरीर में प्रवेश किया। इसीलिए हर इंसान के अंदर परमात्मा है।\\n\\n<strong>सबसे बड़ी सीख:</strong> "प्रज्ञानम् ब्रह्म" — यानी जो देखने की, सुनने की, सोचने की शक्ति है — वही ब्रह्म है। वह शक्ति हमारे अंदर है।`,\n           en:`<strong>Key Teaching:</strong> This is a short, accessible Upanishad — the best one to start with.\\n\\nIt describes how creation happened: In the beginning only the Self existed. It thought, "I am alone, let me create more." It created mind, then space, then air, then water, then earth.\\n\\nThen it created humans and entered into them. This is why every human contains the divine within.\\n\\n<strong>Greatest Teaching:</strong> "Prajna brahma" — the power of seeing, hearing, and thinking IS Brahman. That power is within us.`},\n   lessons:[\n     {icon:\'🌱\',t:{hi:\'सृष्टि\',en:\'Creation\'},d:{hi:\'परमात्मा ने अपनी इच्छा से ब्रह्मांड बनाया — एकाकीपन से बाहर।\',en:\'God created the universe from His own will — out of solitude.\'}},\n     {icon:\'👤\',t:{hi:\'मानव\',en:\'Human Being\'},d:{hi:\'हर इंसान के अंदर परमात्मा है — हम उसकी सबसे बड़ी रचना हैं।\',en:\'Every human contains the divine within — we are His greatest creation.\'}},\n     {icon:\'💡\',t:{hi:\'चेतना\',en:\'Consciousness\'},d:{hi:\'चेतना (जागरूकता) ही ब्रह्म है — यही "प्रज्ञानम् ब्रह्म" का अर्थ है।\',en:\'Consciousness (awareness) IS Brahman — this is the meaning of "Prajnanam Brahma."\'}},\n     {icon:\'🔄\',t:{hi:\'आत्मा\',en:\'The Self\'},d:{hi:\'जो देखता है, सुनता है, सोचता है — वह परमात्मा ही है।\',en:\'That which sees, hears, thinks — that IS the divine Self.\'}},\n   ],\n   verse:{s:\'प्रज्ञानं ब्रह्म।\',a:{hi:\'"ज्ञान (चेतना) ही ब्रह्म है।" — यह ऋग्वेद का महावाक्य है।\',en:\'"Consciousness is Brahman." — The great saying of the Rigveda.\'},src:\'ऐतरेय उपनिषद 3.3\'},\n   tags:{hi:[\'सृष्टि\',\'चेतना\',\'आत्मा\'],en:[\'Creation\',\'Consciousness\',\'Self\']}},\n\n  {id:\'kaushitaki\',name:{hi:\'कौषीतकि उपनिषद\',en:\'Kaushitaki Upanishad\'},\n   veda:{hi:\'ऋग्वेद\',en:\'Rigveda\'},vedaId:\'rig\',vedaColor:\'#BA7517\',\n   chapters:{hi:\'4 अध्याय\',en:\'4 Chapters\'},verses:{hi:\'~60 श्लोक\',en:\'~60 Verses\'},\n   level:{hi:\'मध्यम\',en:\'Intermediate\'},\n   teaser:{hi:\'इंद्र की शिक्षा — प्राण ही ब्रह्म है।\',en:\'Indra\\\'s teaching — Prana is Brahman.\'},\n   mv:\'प्राणो ब्रह्म\',\n   mv_arth:{hi:\'"प्राण (जीवन शक्ति) ही ब्रह्म है"\',en:\'"Prana (life force) is Brahman"\'},\n   story:{hi:`इस उपनिषद में इंद्र (देवराज) और प्रतर्दन की मशहूर कहानी है।\\n\\nप्रतर्दन स्वर्ग पहुंचे। इंद्र ने कहा — "मांगो, क्या चाहते हो?" प्रतर्दन ने कहा — "तुम जो सबसे अच्छा समझो, वो दो।"\\n\\nइंद्र ने कहा — <em>"मुझे जानो। यही सबसे बड़ा ज्ञान है। मैं ही प्राण हूं। मैं ही प्रज्ञा (चेतना) हूं। मुझे जानने वाला सब कुछ जान लेता है।"</em>\\n\\nइस उपनिषद की मुख्य सीख है — <strong>प्राण (सांस/जीवन शक्ति) ही ब्रह्मन है।</strong> जब हम सांस लेते हैं, हम परमात्मा को महसूस कर रहे होते हैं।`,\n           en:`This Upanishad contains the famous story of Indra and Pratardana.\\n\\nPratardana reached heaven. Indra said — "Ask for anything you want." Pratardana said — "Give me whatever you think is best for me."\\n\\nIndra replied — <em>"Know me. That is the greatest knowledge. I am Prana. I am Prajna (consciousness). One who knows me knows everything."</em>\\n\\nThe key teaching: <strong>Prana (breath/life force) is Brahman.</strong> When we breathe, we are experiencing the divine.`},\n   lessons:[\n     {icon:\'💨\',t:{hi:\'प्राण\',en:\'Prana\'},d:{hi:\'जीवन शक्ति (सांस) ही परमात्मा है — यह हर पल हमारे साथ है।\',en:\'Life force (breath) is the divine — it is with us every moment.\'}},\n     {icon:\'👁️\',t:{hi:\'चेतना\',en:\'Consciousness\'},d:{hi:\'जागरूकता ही ब्रह्म है — सोने में, जागने में, हर अवस्था में।\',en:\'Awareness is Brahman — in sleep, in waking, in every state.\'}},\n     {icon:\'❓\',t:{hi:\'सही सवाल\',en:\'Right Question\'},d:{hi:\'सबसे बड़ा ज्ञान मांगना — यही असली ज्ञान की शुरुआत है।\',en:\'Asking for the highest wisdom — this is the beginning of real knowledge.\'}},\n     {icon:\'🌬️\',t:{hi:\'श्वास\',en:\'Breath\'},d:{hi:\'हर सांस में परमात्मा है। श्वास पर ध्यान ही ध्यान है।\',en:\'God is in every breath. Awareness of breath is meditation.\'}},\n   ],\n   verse:{s:\'प्राणो ब्रह्म, प्रज्ञा आत्मा।\',a:{hi:\'"प्राण ही ब्रह्म है, चेतना ही आत्मा है।"\',en:\'"Prana is Brahman, consciousness is the Self."\'},src:\'कौषीतकि उपनिषद 3.2\'},\n   tags:{hi:[\'प्राण\',\'चेतना\',\'इंद्र\'],en:[\'Prana\',\'Consciousness\',\'Indra\']}},\n\n  {id:\'chandogya\',name:{hi:\'छांदोग्य उपनिषद\',en:\'Chandogya Upanishad\'},\n   veda:{hi:\'सामवेद\',en:\'Samaveda\'},vedaId:\'sama\',vedaColor:\'#185FA5\',\n   chapters:{hi:\'8 अध्याय\',en:\'8 Chapters\'},verses:{hi:\'~600 श्लोक\',en:\'~600 Verses\'},\n   level:{hi:\'मध्यम\',en:\'Intermediate\'},\n   teaser:{hi:\'"तत् त्वम् असि" — नमक और पानी की कहानी।\',en:\'"Tat tvam asi" — the story of salt and water.\'},\n   mv:\'तत् त्वम् असि\',\n   mv_arth:{hi:\'"वह तुम हो" — परमात्मा और आत्मा एक हैं\',en:\'"That thou art" — God and the soul are one\'},\n   story:{hi:`<strong>ॐ से शुरुआत:</strong> यह ॐ की महिमा से शुरू होता है — "ॐ सबसे श्रेष्ठ है।"\\n\\n<strong>मशहूर कहानी — नमक और पानी:</strong>\\n\\nएक बार श्वेतकेतु 12 साल गुरुकुल में पढ़कर घर आया। वह बहुत घमंडी था। उसके पिता उद्दालक आरुणि ने पूछा — "क्या तुमने वो ज्ञान सीखा जिससे सब कुछ जाना जा सके?"\\n\\nश्वेतकेतु ने कहा — "नहीं।"\\n\\nतब उद्दालक ने एक गिलास पानी में नमक डाला और कहा — "कल सुबह आना।" सुबह उन्होंने कहा — "नमक लाओ।" श्वेतकेतु ने देखा — नमक दिख नहीं रहा। उद्दालक ने कहा — "पानी पीओ — नमकीन है ना? तो नमक है, लेकिन दिखता नहीं। वैसे ही परमात्मा हर चीज़ में है — दिखता नहीं, लेकिन है।"\\n\\n<strong>तत् त्वम् असि — "वह तुम हो"</strong> — यही इस उपनिषद की सबसे बड़ी बात है।`,\n           en:`<strong>Begins with Om:</strong> "Om is the most exalted of all."\\n\\n<strong>Famous Story — Salt and Water:</strong>\\n\\nShvetaketu returned home after 12 years of study, very proud. His father Uddalaka asked — "Did you learn that one thing by knowing which everything becomes known?"\\n\\nShvetaketu said — "No."\\n\\nUddalaka dissolved salt in water and said — "Come tomorrow." Next morning: "Bring me the salt." Shvetaketu looked — no salt visible. Uddalaka said — "Taste the water — salty, isn\'t it? The salt is there but invisible. Just so, God is in everything — invisible but present everywhere."\\n\\n<strong>Tat tvam asi — "That thou art"</strong> — the greatest teaching of this Upanishad.`},\n   lessons:[\n     {icon:\'🧂\',t:{hi:\'नमक और पानी\',en:\'Salt & Water\'},d:{hi:\'जैसे नमक पानी में अदृश्य है लेकिन हर जगह — वैसे ही परमात्मा।\',en:\'Like salt dissolved in water — invisible yet everywhere. So is God.\'}},\n     {icon:\'🎵\',t:{hi:\'ॐ\',en:\'Om\'},d:{hi:\'ॐ सबसे श्रेष्ठ ध्वनि है — सारी सृष्टि इससे बनी है।\',en:\'Om is the most exalted sound — all creation emerged from it.\'}},\n     {icon:\'🤝\',t:{hi:\'एकता\',en:\'Unity\'},d:{hi:\'तुम और परमात्मा अलग नहीं — "तत् त्वम् असि।"\',en:\'You and God are not separate — "Tat tvam asi."\'}},\n     {icon:\'📚\',t:{hi:\'ज्ञान\',en:\'True Knowledge\'},d:{hi:\'असली ज्ञान वो है जिससे हर चीज़ जानी जा सके — वह है ब्रह्म-ज्ञान।\',en:\'True knowledge is that which makes everything known — knowledge of Brahman.\'}},\n   ],\n   verse:{s:\'तत् त्वम् असि, श्वेतकेतो।\',a:{hi:\'"वह (परमात्मा) तुम हो, श्वेतकेतु।" — उद्दालक आरुणि अपने बेटे को।\',en:\'"That thou art, Shvetaketu." — Uddalaka Aruni to his son.\'},src:\'छांदोग्य उपनिषद 6.8.7\'},\n   tags:{hi:[\'एकता\',\'ॐ\',\'नमक-पानी\'],en:[\'Unity\',\'Om\',\'Salt-Water\']}},\n\n  {id:\'kena\',name:{hi:\'केन उपनिषद\',en:\'Kena Upanishad\'},\n   veda:{hi:\'सामवेद\',en:\'Samaveda\'},vedaId:\'sama\',vedaColor:\'#185FA5\',\n   chapters:{hi:\'4 भाग\',en:\'4 Sections\'},verses:{hi:\'~34 श्लोक\',en:\'~34 Verses\'},\n   level:{hi:\'मध्यम\',en:\'Intermediate\'},\n   teaser:{hi:\'"किसके द्वारा?" — परमात्मा सब के पीछे है।\',en:\'"By whom?" — God is behind everything.\'},\n   mv:\'केनेषितं पतति प्रेषितं मनः\',\n   mv_arth:{hi:\'"किसके आदेश से मन चलता है?"\',en:\'"By whose command does the mind move?"\'},\n   story:{hi:`<strong>शुरुआत एक सवाल से:</strong> "किसके कहने पर मन सोचता है? किसके कारण सांस चलती है? किसके आदेश से आंख देखती है? कौन कान को सुनाता है?"\\n\\nजवाब है — <strong>वह परमात्मा जो आंख की आंख है, कान का कान है, मन का मन है।</strong> वह खुद आंख से नहीं देखा जा सकता — लेकिन उसी के कारण आंख देखती है।\\n\\n<strong>इंद्र और उमा की कहानी:</strong> एक बार एक यक्ष (रहस्यमय शक्ति) प्रकट हुई। इंद्र, वायु, अग्नि — किसी को समझ नहीं आया वह कौन है। अंत में देवी उमा (पार्वती) आईं और बताया — "वह ब्रह्म था। उसी की शक्ति से तुम जीतते हो।"\\n\\n<strong>मुख्य सीख:</strong> परमात्मा सब के पीछे है — लेकिन वह खुद किसी के द्वारा नहीं चलता।`,\n           en:`<strong>Opens with a question:</strong> "By whose command does the mind think? By whose power does life move? By whose order does the eye see? Who makes the ear hear?"\\n\\nAnswer: <strong>That Brahman which is the eye of the eye, ear of the ear, mind of the mind.</strong> It cannot be seen by the eye — yet the eye sees because of it.\\n\\n<strong>Story of Indra and Uma:</strong> A mysterious power (Yaksha) appeared. Indra, Vayu, Agni — none could understand who it was. Finally Goddess Uma (Parvati) came and explained — "That was Brahman. By Its power alone do you conquer."\\n\\n<strong>Key Teaching:</strong> God is behind everything — yet God itself is caused by nothing.`},\n   lessons:[\n     {icon:\'🎭\',t:{hi:\'पर्दे के पीछे\',en:\'Behind the Curtain\'},d:{hi:\'परमात्मा सब के पीछे है — वही देखने वाला, सुनने वाला, सोचने वाला है।\',en:\'God is behind everything — the real seer, hearer, thinker behind all experiences.\'}},\n     {icon:\'❓\',t:{hi:\'असली सवाल\',en:\'Real Question\'},d:{hi:\'"मैं कौन हूं?" नहीं — "कौन है जो मेरे अंदर देखता, सुनता, सोचता है?"\',en:\'Not "Who am I?" but "Who is it within me that sees, hears and thinks?"\'}},\n     {icon:\'👁️\',t:{hi:\'परे और पास\',en:\'Beyond Yet Near\'},d:{hi:\'परमात्मा आंख से नहीं देखा जा सकता — लेकिन वह सबसे करीब है।\',en:\'God cannot be seen by the eye — yet is closer to us than anything.\'}},\n     {icon:\'🏆\',t:{hi:\'विनम्रता\',en:\'Humility\'},d:{hi:\'इंद्र भी नहीं समझ सके — इसलिए विनम्र रहना ज़रूरी है।\',en:\'Even Indra could not understand — humility is essential on the path to wisdom.\'}},\n   ],\n   verse:{s:\'न तत्र चक्षुर्गच्छति न वाग्गच्छति नो मनः।\',a:{hi:\'"वहां आंख नहीं जाती, वाणी नहीं जाती, मन नहीं जाता।" — परमात्मा इंद्रियों से परे है।\',en:\'"There the eye does not go, nor speech, nor the mind." — God is beyond all the senses.\'},src:\'केन उपनिषद 1.3\'},\n   tags:{hi:[\'इंद्र\',\'उमा\',\'इंद्रियां\'],en:[\'Indra\',\'Uma\',\'Senses\']}},\n\n  {id:\'brihadaranyaka\',name:{hi:\'बृहदारण्यक उपनिषद\',en:\'Brihadaranyaka Upanishad\'},\n   veda:{hi:\'यजुर्वेद\',en:\'Yajurveda\'},vedaId:\'yajur\',vedaColor:\'#3B6D11\',\n   chapters:{hi:\'6 अध्याय\',en:\'6 Chapters\'},verses:{hi:\'~400 श्लोक\',en:\'~400+ Verses\'},\n   level:{hi:\'उन्नत\',en:\'Advanced\'},\n   teaser:{hi:\'सबसे बड़ा उपनिषद। याज्ञवल्क्य की शिक्षाएं। "अहम् ब्रह्मास्मि।"\',en:\'Largest Upanishad. Yajnavalkya\\\'s teachings. "I am Brahman."\'},\n   mv:\'अहम् ब्रह्मास्मि\',\n   mv_arth:{hi:\'"मैं ही ब्रह्म हूं" — आत्मा = परमात्मा\',en:\'"I am Brahman" — the Self = the Ultimate\'},\n   story:{hi:`<strong>सबसे बड़ा शास्त्रार्थ:</strong> राजा जनक ने एक बड़ी सभा बुलाई। घोषणा की — "जो सबसे बड़ा विद्वान है, वो 1,000 गायें ले जाए।" ऋषि याज्ञवल्क्य ने अपने शिष्य को गायें हांकने को कहा। सब चकित। फिर शास्त्रार्थ हुआ।\\n\\n<strong>गार्गी का सवाल:</strong> गार्गी (महिला दार्शनिक) ने पूछा — "यह धरती किस में बुनी है?" याज्ञवल्क्य ने जवाब दिया। उन्होंने पूछते-पूछते अंत में पूछा — "ब्रह्म किस में बुना है?" याज्ञवल्क्य बोले — "इससे ज़्यादा मत पूछो, वरना तुम्हारा सिर फट जाएगा।"\\n\\n<strong>मैत्रेयी की कहानी:</strong> याज्ञवल्क्य जंगल जाने लगे। पत्नी मैत्रेयी ने पूछा — "अगर सारी धरती का सोना मिल जाए, तो क्या अमर हो सकते हैं?" जवाब — "नहीं।" मैत्रेयी ने कहा — "तो उसे मत दो। मुझे वो ज्ञान दो जिससे अमरता मिले।" फिर याज्ञवल्क्य ने "अहम् ब्रह्मास्मि" की शिक्षा दी।`,\n           en:`<strong>The Great Debate:</strong> King Janaka called a grand assembly. He declared — "Whoever is the greatest scholar, take these 1,000 cows." Sage Yajnavalkya told his student to drive the cows away. Everyone was stunned. Then the debate began.\\n\\n<strong>Gargi\'s Question:</strong> Gargi (the woman philosopher) asked — "In what is the earth woven?" Yajnavalkya answered. She kept asking deeper and deeper, finally: "In what is Brahman woven?" Yajnavalkya said — "Do not ask further, or your head will fall off."\\n\\n<strong>Maitreyi\'s Story:</strong> Yajnavalkya was about to leave for the forest. His wife Maitreyi asked — "If I had all the wealth of the earth, would I become immortal?" Answer — "No." Maitreyi: "Then don\'t give it to me. Give me the knowledge that brings immortality." Then Yajnavalkya taught "Aham Brahmasmi."`},\n   lessons:[\n     {icon:\'🔥\',t:{hi:\'आत्म-ज्ञान\',en:\'Self-Knowledge\'},d:{hi:\'"अहम् ब्रह्मास्मि" — मैं ही ब्रह्म हूं। यही सबसे बड़ा ज्ञान है।\',en:\'"Aham Brahmasmi" — I am Brahman. This is the greatest knowledge.\'}},\n     {icon:\'👩\u200d🏫\',t:{hi:\'गार्गी\',en:\'Gargi\'},d:{hi:\'भारत की पहली महिला दार्शनिक ने याज्ञवल्क्य को चुनौती दी।\',en:\'India\\\'s first woman philosopher challenged even the great Yajnavalkya.\'}},\n     {icon:\'💎\',t:{hi:\'असली संपत्ति\',en:\'Real Wealth\'},d:{hi:\'सोना-चांदी से अमरता नहीं मिलती — ब्रह्म-ज्ञान से मिलती है।\',en:\'Gold and silver don\\\'t bring immortality — Brahman-knowledge does.\'}},\n     {icon:\'🌅\',t:{hi:\'नेति नेति\',en:\'Neti Neti\'},d:{hi:\'"न यह, न यह" — परमात्मा को हटाते-हटाते जानो।\',en:\'"Not this, not this" — know God by eliminating everything that is not God.\'}},\n   ],\n   verse:{s:\'अयम् आत्मा ब्रह्म।\\nअहं ब्रह्मास्मि।\',a:{hi:\'"यह आत्मा ही ब्रह्म है। मैं ही ब्रह्म हूं।"\',en:\'"This Self is Brahman. I am Brahman."\'},src:\'बृहदारण्यक उपनिषद 4.4.5 / 1.4.10\'},\n   tags:{hi:[\'याज्ञवल्क्य\',\'गार्गी\',\'मैत्रेयी\'],en:[\'Yajnavalkya\',\'Gargi\',\'Maitreyi\']}},\n\n  {id:\'isha\',name:{hi:\'ईशावास्योपनिषद\',en:\'Isha Upanishad\'},\n   veda:{hi:\'यजुर्वेद\',en:\'Yajurveda\'},vedaId:\'yajur\',vedaColor:\'#3B6D11\',\n   chapters:{hi:\'1 अध्याय\',en:\'1 Chapter\'},verses:{hi:\'18 श्लोक\',en:\'18 Verses\'},\n   level:{hi:\'शुरुआती\',en:\'Beginner\'},\n   teaser:{hi:\'सबसे छोटा — 18 श्लोक। गांधीजी का पसंदीदा।\',en:\'Shortest Upanishad — 18 verses. Gandhi\\\'s favorite.\'},\n   mv:\'ईशावास्यमिदम् सर्वम्\',\n   mv_arth:{hi:\'"यह पूरा जगत परमात्मा में बसा है"\',en:\'"All this universe is pervaded by God"\'},\n   story:{hi:`<strong>शुरुआत:</strong> "ईशावास्यमिदम् सर्वम् यत्किञ्च जगत्यां जगत्" — "यह पूरी दुनिया में जो कुछ भी है, वह सब परमात्मा में बसा है।"\\n\\n<strong>गांधीजी का प्यार:</strong> महात्मा गांधी ने कहा — "अगर सारे धर्म-ग्रंथ नष्ट हो जाएं और सिर्फ ईशावास्योपनिषद का पहला श्लोक बचे, तो इंसान को ज़िंदगी जीने के लिए और कुछ नहीं चाहिए।"\\n\\n<strong>मुख्य शिक्षाएं:</strong>\\n• <strong>त्याग:</strong> काम करो लेकिन फल की चाहत मत रखो\\n• <strong>सर्वत्र ईश्वर:</strong> हर जगह परमात्मा है — इसलिए किसी को नुकसान मत पहुंचाओ\\n• <strong>भेद नहीं:</strong> जो सब में एक ही देखता है, उसे कोई दुख नहीं\\n• <strong>ज्ञान और कर्म:</strong> दोनों ज़रूरी हैं — अकेले से मुक्ति नहीं`,\n           en:`<strong>Opening:</strong> "Isavasyam idam sarvam yat kincha jagatyam jagat" — "Whatever exists in this ever-moving world is pervaded by God."\\n\\n<strong>Gandhi\'s Love:</strong> Mahatma Gandhi said — "If all scriptures were destroyed and only the first verse of the Isha Upanishad remained, there would be enough wisdom to guide humanity."\\n\\n<strong>Key Teachings:</strong>\\n• <strong>Renunciation:</strong> Act, but without clinging to results\\n• <strong>God is Everywhere:</strong> God pervades everything — so harm no one\\n• <strong>No Division:</strong> One who sees the Self in all beings experiences no sorrow\\n• <strong>Knowledge & Action:</strong> Both are necessary — neither alone leads to liberation`},\n   lessons:[\n     {icon:\'🌍\',t:{hi:\'सर्वत्र परमात्मा\',en:\'God Everywhere\'},d:{hi:\'हर चीज़ में, हर जगह, हर इंसान में — परमात्मा है।\',en:\'In everything, everywhere, in every person — God is present.\'}},\n     {icon:\'🎯\',t:{hi:\'निष्काम कर्म\',en:\'Desireless Action\'},d:{hi:\'काम करो पूरी लगन से, लेकिन फल की चिंता मत करो।\',en:\'Work with full dedication, but do not be attached to the results.\'}},\n     {icon:\'🕊️\',t:{hi:\'त्याग\',en:\'Renunciation\'},d:{hi:\'जो लालच से मुक्त है — उसके लिए सब कुछ है।\',en:\'One who is free from greed — for them everything is available.\'}},\n     {icon:\'💝\',t:{hi:\'एकत्व\',en:\'Oneness\'},d:{hi:\'जो सब में एक ही आत्मा देखता है, उसे कोई दुख नहीं।\',en:\'One who sees the same Self in all beings experiences no sorrow or delusion.\'}},\n   ],\n   verse:{s:\'ईशावास्यमिदम् सर्वम्\\nयत्किञ्च जगत्यां जगत्।\\nतेन त्यक्तेन भुञ्जीथा\\nमा गृधः कस्यस्विद्धनम्॥\',a:{hi:\'"इस पूरे जगत में जो कुछ भी है — वह परमात्मा में बसा है। त्याग भाव से भोग करो — किसी के धन की लालच मत करो।"\',en:\'"Whatever exists in this world is pervaded by God. Enjoy through renunciation — do not covet anyone\\\'s wealth."\'},src:\'ईशावास्योपनिषद 1 — पहला श्लोक\'},\n   tags:{hi:[\'गांधी\',\'त्याग\',\'एकत्व\'],en:[\'Gandhi\',\'Renunciation\',\'Oneness\']}},\n\n  {id:\'mundaka\',name:{hi:\'मुंडकोपनिषद\',en:\'Mundaka Upanishad\'},\n   veda:{hi:\'अथर्ववेद\',en:\'Atharvaveda\'},vedaId:\'atharva\',vedaColor:\'#534AB7\',\n   chapters:{hi:\'3 मुंडक\',en:\'3 Mundakas\'},verses:{hi:\'~64 श्लोक\',en:\'~64 Verses\'},\n   level:{hi:\'मध्यम\',en:\'Intermediate\'},\n   teaser:{hi:\'दो तरह का ज्ञान — कौन सा असली?\',en:\'Two kinds of knowledge — which is real?\'},\n   mv:\'ब्रह्म वेद ब्रह्मैव भवति\',\n   mv_arth:{hi:\'"जो ब्रह्म को जाने, वह ब्रह्म बन जाए"\',en:\'"He who knows Brahman becomes Brahman"\'},\n   story:{hi:`<strong>शुरुआत का सवाल:</strong> ऋषि शौनक ने आंगिरस के पास जाकर पूछा — "हे भगवन, क्या एक ऐसी चीज़ है जिसे जानने से सब कुछ जाना जा सके?"\\n\\n<strong>दो तरह का ज्ञान:</strong>\\n• <strong>अपरा विद्या</strong> (निम्न ज्ञान) — वेद, व्याकरण, गणित, ज्योतिष, संगीत, भाषाशास्त्र\\n• <strong>परा विद्या</strong> (उच्च ज्ञान) — जिससे अविनाशी ब्रह्म जाना जाए\\n\\n<strong>आत्मा अमर है:</strong> "यह आत्मा किसी हथियार से नहीं कटती, आग से नहीं जलती, पानी से नहीं भीगती, हवा से नहीं सूखती।" — यही शब्द बाद में भगवद्गीता में भी आए!\\n\\n<strong>शिकारी और दो पक्षी:</strong> एक पेड़ पर दो पक्षी बैठे हैं। एक फल खाता है, दूसरा सिर्फ देखता है। पहला पक्षी हमारी आत्मा (जीव) है जो संसार में लिप्त है। दूसरा परमात्मा (ब्रह्म) है — निरपेक्ष, साक्षी।`,\n           en:`<strong>Opening Question:</strong> Sage Shaunaka approached Angiras and asked — "O Revered One, is there one thing by knowing which everything becomes known?"\\n\\n<strong>Two Kinds of Knowledge:</strong>\\n• <strong>Apara Vidya</strong> (Lower Knowledge) — Vedas, grammar, mathematics, astronomy, music, linguistics\\n• <strong>Para Vidya</strong> (Higher Knowledge) — by which the imperishable Brahman is known\\n\\n<strong>The Immortal Self:</strong> "The Self is not cut by weapons, not burned by fire, not wetted by water, not dried by wind." — These same words appear later in the Bhagavad Gita!\\n\\n<strong>Two Birds on a Tree:</strong> Two birds sit on one tree. One eats the fruits; the other only watches. The first is the individual soul (Jiva) caught in the world. The second is Brahman — detached, witness.`},\n   lessons:[\n     {icon:\'🎓\',t:{hi:\'दो ज्ञान\',en:\'Two Knowledges\'},d:{hi:\'स्कूल की पढ़ाई और ब्रह्म-ज्ञान — दोनों ज़रूरी, लेकिन दूसरा सबसे ऊपर।\',en:\'School learning and Brahman-knowledge — both needed, but the latter is supreme.\'}},\n     {icon:\'🐦\',t:{hi:\'दो पक्षी\',en:\'Two Birds\'},d:{hi:\'एक पक्षी (आत्मा) भोग करता है, दूसरा (परमात्मा) सिर्फ देखता है।\',en:\'One bird (soul) enjoys; the other (Brahman) only watches — be the witness.\'}},\n     {icon:\'⚡\',t:{hi:\'अमर आत्मा\',en:\'Immortal Self\'},d:{hi:\'आत्मा को न काटा जा सकता है, न जलाया जा सकता है। यह अमर है।\',en:\'The Self cannot be cut, burned, or destroyed. It is immortal.\'}},\n     {icon:\'🙏\',t:{hi:\'विनम्रता\',en:\'Surrender\'},d:{hi:\'"ब्रह्म वेद ब्रह्मैव भवति" — जो ब्रह्म को जाने, वह ब्रह्म बन जाए।\',en:\'"He who knows Brahman becomes Brahman" — knowledge transforms the knower.\'}}\n   ],\n   verse:{s:\'ब्रह्म वेद ब्रह्मैव भवति।\',a:{hi:\'"जो ब्रह्म को जान लेता है, वह ब्रह्म ही बन जाता है।"\',en:\'"He who knows Brahman becomes Brahman itself."\'},src:\'मुंडकोपनिषद 3.2.9\'},\n   tags:{hi:[\'दो पक्षी\',\'अमर आत्मा\',\'ज्ञान\'],en:[\'Two Birds\',\'Immortal Self\',\'Knowledge\']}},\n\n  {id:\'mandukya\',name:{hi:\'माण्डूक्य उपनिषद\',en:\'Mandukya Upanishad\'},\n   veda:{hi:\'अथर्ववेद\',en:\'Atharvaveda\'},vedaId:\'atharva\',vedaColor:\'#534AB7\',\n   chapters:{hi:\'1 अध्याय\',en:\'1 Chapter\'},verses:{hi:\'12 श्लोक\',en:\'12 Verses\'},\n   level:{hi:\'उन्नत\',en:\'Advanced\'},\n   teaser:{hi:\'12 श्लोक — ॐ की 4 अवस्थाएं। सबसे गहरा।\',en:\'12 verses — 4 states of Om. The most profound.\'},\n   mv:\'अयम् आत्मा ब्रह्म\',\n   mv_arth:{hi:\'"यह आत्मा ही ब्रह्म है"\',en:\'"This Self is Brahman"\'},\n   story:{hi:`<strong>आदि शंकराचार्य ने कहा:</strong> "माण्डूक्य उपनिषद अकेला ही मोक्ष के लिए काफी है।"\\n\\nसिर्फ 12 श्लोक — लेकिन वेदांत का पूरा दर्शन इसमें है।\\n\\n<strong>ॐ की व्याख्या:</strong>\\n\\n"ॐ" — यह अक्षर ही सब कुछ है। जो भूत, वर्तमान, भविष्य है — वह ॐ है।\\n\\n<strong>चेतना की 4 अवस्थाएं:</strong>\\n\\n• <strong>अ (जागृति):</strong> जागने की अवस्था — हम दुनिया देखते हैं\\n• <strong>उ (स्वप्न):</strong> सपने की अवस्था — मन अपनी दुनिया बनाता है\\n• <strong>म (सुषुप्ति):</strong> गहरी नींद — कोई विचार नहीं, शांति\\n• <strong>मौन — तुरीय:</strong> "चौथी अवस्था" — न जागना, न सपना, न नींद। यह शुद्ध चेतना है। यही परमात्मा है।\\n\\n<strong>तुरीय क्या है?</strong> यह वह अवस्था है जो तीनों को देखती है — जैसे स्क्रीन जो सिनेमा देखने में खुद नहीं बदलती। तुरीय = साक्षी = शुद्ध आत्मा = ब्रह्म।`,\n           en:`<strong>Adi Shankaracharya said:</strong> "The Mandukya Upanishad alone is sufficient for liberation."\\n\\nOnly 12 verses — yet it contains the complete philosophy of Vedanta.\\n\\n<strong>Explanation of Om:</strong>\\n\\n"Om" — this syllable is all this. Whatever exists — past, present, future — that is Om.\\n\\n<strong>4 States of Consciousness:</strong>\\n\\n• <strong>A (Waking):</strong> We experience the outer world\\n• <strong>U (Dream):</strong> The mind creates its own world\\n• <strong>M (Deep Sleep):</strong> No thoughts, only peace\\n• <strong>Silence — Turiya:</strong> "The Fourth State" — not waking, not dreaming, not sleeping. This is pure consciousness. This is Brahman.\\n\\n<strong>What is Turiya?</strong> It is the state that witnesses all three — like a cinema screen that doesn\'t change while films play on it. Turiya = Witness = Pure Self = Brahman.`},\n   lessons:[\n     {icon:\'🔤\',t:{hi:\'ॐ का अर्थ\',en:\'Meaning of Om\'},d:{hi:\'अ+उ+म+मौन — चार अवस्थाएं, एक ही परमात्मा।\',en:\'A+U+M+Silence — four states, one Brahman.\'}},\n     {icon:\'😴\',t:{hi:\'नींद में ब्रह्म\',en:\'God in Sleep\'},d:{hi:\'गहरी नींद में कोई दुख नहीं — यह ब्रह्म की झलक है।\',en:\'In deep sleep there is no suffering — this is a glimpse of Brahman.\'}},\n     {icon:\'🎬\',t:{hi:\'साक्षी\',en:\'Witness\'},d:{hi:\'तुरीय वह स्क्रीन है जिस पर तीनों अवस्थाएं चलती हैं — लेकिन वह खुद नहीं बदलती।\',en:\'Turiya is the screen on which all three states play — but it itself never changes.\'}},\n     {icon:\'🌟\',t:{hi:\'अयम् आत्मा ब्रह्म\',en:\'This Self is Brahman\'},d:{hi:\'तुम्हारे अंदर जो है और बाहर जो है — वह एक ही है।\',en:\'What is within you and what is outside — they are one and the same.\'}},\n   ],\n   verse:{s:\'ओमित्येतदक्षरमिदँ सर्वम्।\\nतस्योपव्याख्यानम्।\\nभूतं भवद् भविष्यदिति सर्वमोंकार एव।\',a:{hi:\'"ॐ — यह अक्षर ही सब कुछ है। जो भूत था, जो वर्तमान है, जो भविष्य होगा — वह सब ॐ ही है।"\',en:\'"Om — this syllable is all this. Whatever exists — past, present, future — all that is just Om."\'},src:\'माण्डूक्य उपनिषद 1\'},\n   tags:{hi:[\'ॐ\',\'तुरीय\',\'4 अवस्थाएं\'],en:[\'Om\',\'Turiya\',\'4 States\']}},\n];\n\nconst RISHIS=[\n  {name:{hi:\'याज्ञवल्क्य\',en:\'Yajnavalkya\'},icon:\'🕯\',veda:{hi:\'यजुर्वेद\',en:\'Yajurveda\'},\n   d:{hi:\'बृहदारण्यक उपनिषद के सबसे बड़े ऋषि। राजा जनक के दरबार में सभी विद्वानों को हराया। उनकी पत्नी मैत्रेयी भी महान दार्शनिक थीं। "नेति नेति" (न यह, न यह) उनकी सबसे मशहूर शिक्षा है। उन्होंने पहले "अहम् ब्रह्मास्मि" कहा।\',\n      en:\'Greatest sage of the Brihadaranyaka Upanishad. Won the grand debate at King Janaka\\\'s court. His wife Maitreyi was also a great philosopher. Famous for "Neti Neti" and "Aham Brahmasmi."\'}},\n  {name:{hi:\'विश्वामित्र\',en:\'Vishwamitra\'},icon:\'⭐\',veda:{hi:\'ऋग्वेद\',en:\'Rigveda\'},\n   d:{hi:\'पहले राजा (क्षत्रिय), फिर तपस्या से ऋषि बने — बहुत दुर्लभ। गायत्री मंत्र की रचना की। राम के गुरु। वशिष्ठ से बड़ी प्रतिस्पर्धा थी। "विश्वामित्र" माने "सारी दुनिया का मित्र।"\',\n      en:\'Originally a king who became a sage through penance — extremely rare. Composed the Gayatri Mantra. Teacher of Rama. Great rivalry with Vashistha. "Vishwamitra" means "friend of the universe."\'}},\n  {name:{hi:\'वशिष्ठ\',en:\'Vashistha\'},icon:\'🌟\',veda:{hi:\'ऋग्वेद\',en:\'Rigveda\'},\n   d:{hi:\'ब्रह्मा के पुत्र और सप्तर्षि में से एक। राजा दशरथ के कुल गुरु। ऋग्वेद का 7वां मंडल उन्होंने लिखा। उनकी पत्नी अरुंधति स्वयं ऋषिका थीं। "योग वशिष्ठ" उनके नाम पर है।\',\n      en:\'Son of Brahma and one of the Seven Sages (Saptarishi). Family priest of King Dasharatha. Composed the 7th Mandala of the Rigveda. His wife Arundhati was also a seeress. "Yoga Vashistha" bears his name.\'}},\n  {name:{hi:\'गार्गी\',en:\'Gargi\'},icon:\'🌺\',veda:{hi:\'यजुर्वेद\',en:\'Yajurveda\'},\n   d:{hi:\'भारत की सबसे पहली ज्ञात महिला दार्शनिक। राजा जनक के दरबार में याज्ञवल्क्य से शास्त्रार्थ किया। उन्हें "ब्रह्मवादिनी" (महिला ब्रह्म-वक्ता) कहते थे। उन्होंने पूछा — "यह सारी दुनिया किस में बुनी है?"\',\n      en:\'India\\\'s first recorded woman philosopher. Debated Yajnavalkya at King Janaka\\\'s court. Called a "Brahmavadini" (female theologian). She asked: "In what is this entire universe woven?"\'}},\n  {name:{hi:\'उद्दालक\',en:\'Uddalaka\'},icon:\'💧\',veda:{hi:\'सामवेद\',en:\'Samaveda\'},\n   d:{hi:\'छांदोग्य उपनिषद में अपने बेटे श्वेतकेतु को "तत् त्वम् असि" सिखाया। नमक-पानी का प्रसिद्ध उदाहरण दिया। वे एक महान शिक्षक थे जो जटिल बातें सरल उदाहरणों से समझाते थे।\',\n      en:\'Taught his son Shvetaketu "Tat tvam asi" in the Chandogya Upanishad. Gave the famous salt-water example. A great teacher who explained profound truths through simple everyday examples.\'}},\n  {name:{hi:\'अथर्वन\',en:\'Atharvan\'},icon:\'🌿\',veda:{hi:\'अथर्ववेद\',en:\'Atharvaveda\'},\n   d:{hi:\'अथर्ववेद के मुख्य ऋषि। अग्नि से जुड़े। जड़ी-बूटियां, चिकित्सा और रक्षा के मंत्रों के ज्ञाता। "अथर्वन" का अर्थ है "अग्नि पुजारी।" उनकी विद्या आम लोगों की ज़िंदगी से जुड़ी थी।\',\n      en:\'Chief sage of the Atharvaveda. Associated with fire. Master of herbal medicine and protective spells. "Atharvan" means "fire priest." His knowledge was rooted in everyday life.\'}},\n];\nconst DEITIES=[\n  {name:{hi:\'अग्नि\',en:\'Agni\'},role:{hi:\'अग्नि देव\',en:\'God of Fire\'},icon:\'🔥\',c:\'#E8621A\',\n   d:{hi:\'अग्नि देव सबसे ज़रूरी वैदिक देव हैं — मनुष्यों और देवताओं के बीच दूत। यज्ञ की आहुति को देवताओं तक पहुंचाते हैं। ऋग्वेद का पहला मंत्र इन्हीं को है। इन्हें "जातवेद" (सब जानने वाला) भी कहते हैं।\',\n      en:\'The most essential Vedic deity — the divine messenger between humans and gods. Carries sacrificial offerings to the divine realm. The Rigveda opens with a hymn to Agni. Called "Jatavedas" (one who knows all beings).\'}},\n  {name:{hi:\'इंद्र\',en:\'Indra\'},role:{hi:\'देवराज\',en:\'King of Gods\'},icon:\'⚡\',c:\'#185FA5\',\n   d:{hi:\'वैदिक देवताओं के राजा। बिजली, तूफान और बारिश के देव। अजगर वृत्र को मारकर ब्रह्मांडीय पानी आज़ाद किया — ऋग्वेद की सबसे मशहूर कहानी। बाद में पुराणों में उनकी स्थिति कम हुई।\',\n      en:\'King of the Vedic gods — deity of lightning, storms and rain. Slew the serpent Vritra to release the cosmic waters — Rigveda\\\'s most famous story. Most prominent deity in the Rigveda.\'}},\n  {name:{hi:\'वरुण\',en:\'Varuna\'},role:{hi:\'जल व न्याय देव\',en:\'God of Water & Justice\'},icon:\'🌊\',c:\'#0E7490\',\n   d:{hi:\'पानी, समुद्र, रात के आकाश और नैतिक कानून के देव। सब कुछ देखते हैं — उनके "जासूस" पूरी दुनिया में हैं। जो सच्चे मन से माफी मांगे, वे माफ कर देते हैं।\',\n      en:\'God of water, night sky and moral law. His spies watch all deeds everywhere. He forgives those who sincerely repent. Guardian of Rita (cosmic order).\'}},\n  {name:{hi:\'सूर्य\',en:\'Surya\'},role:{hi:\'सूर्य देव\',en:\'Sun God\'},icon:\'☀️\',c:\'#D97706\',\n   d:{hi:\'रोशनी, ज्ञान और जीवन के देव। गायत्री मंत्र इन्हीं को समर्पित है। उनके रथ में 7 घोड़े हैं — 7 रंग और 7 दिनों का प्रतीक। पुत्री यमुना नदी, पुत्र यम (मृत्यु देव)।\',\n      en:\'God of light, wisdom and life. The Gayatri Mantra is addressed to Surya. His chariot has 7 horses — 7 colors of light and 7 days. His daughter is the river Yamuna; son is Yama (death).\'}},\n];\n\nconst QUIZ=[\n  {q:{hi:\'गायत्री मंत्र किस वेद में है?\',en:\'In which Veda is the Gayatri Mantra?\'},opts:{hi:[\'ऋग्वेद\',\'सामवेद\',\'यजुर्वेद\',\'अथर्ववेद\'],en:[\'Rigveda\',\'Samaveda\',\'Yajurveda\',\'Atharvaveda\']},ans:0,exp:{hi:\'गायत्री मंत्र ऋग्वेद (3.62.10) में है। सूर्य देव को समर्पित।\',en:\'Gayatri Mantra is in Rigveda (3.62.10), addressed to the Sun god.\'}},\n  {q:{hi:\'"तत् त्वम् असि" किस उपनिषद में है?\',en:\'Where does "Tat tvam asi" appear?\'},opts:{hi:[\'बृहदारण्यक\',\'छांदोग्य\',\'ईशावास्य\',\'माण्डूक्य\'],en:[\'Brihadaranyaka\',\'Chandogya\',\'Isha\',\'Mandukya\']},ans:1,exp:{hi:\'"तत् त्वम् असि" छांदोग्य उपनिषद 6.8.7 में है — उद्दालक ने बेटे को सिखाया।\',en:\'"Tat tvam asi" is in Chandogya Upanishad 6.8.7 — Uddalaka teaching his son.\'}},\n  {q:{hi:\'सबसे छोटा उपनिषद कौन सा है?\',en:\'Which is the shortest Upanishad?\'},opts:{hi:[\'ईशावास्य\',\'माण्डूक्य\',\'केन\',\'कठ\'],en:[\'Isha\',\'Mandukya\',\'Kena\',\'Katha\']},ans:0,exp:{hi:\'ईशावास्योपनिषद में सिर्फ 18 श्लोक हैं।\',en:\'Isha Upanishad has only 18 verses — the shortest.\'}},\n  {q:{hi:\'माण्डूक्य उपनिषद में कितने श्लोक हैं?\',en:\'How many verses in the Mandukya Upanishad?\'},opts:{hi:[\'6\',\'12\',\'18\',\'24\'],en:[\'6\',\'12\',\'18\',\'24\']},ans:1,exp:{hi:\'12 श्लोक। शंकराचार्य ने कहा — "अकेला काफी है मोक्ष के लिए।"\',en:\'12 verses. Shankaracharya said — "This alone is sufficient for liberation."\'}},\n  {q:{hi:\'भारत की पहली महिला दार्शनिक कौन थीं?\',en:\'Who was India\\\'s first woman philosopher?\'},opts:{hi:[\'मैत्रेयी\',\'गार्गी\',\'सावित्री\',\'लोपामुद्रा\'],en:[\'Maitreyi\',\'Gargi\',\'Savitri\',\'Lopamudra\']},ans:1,exp:{hi:\'गार्गी वाचकन्वी — राजा जनक के दरबार में याज्ञवल्क्य से शास्त्रार्थ किया।\',en:\'Gargi Vachaknavi — debated Yajnavalkya at King Janaka\\\'s court.\'}},\n  {q:{hi:\'"नेति नेति" किस ऋषि की शिक्षा है?\',en:\'"Neti Neti" — whose teaching?\'},opts:{hi:[\'विश्वामित्र\',\'उद्दालक\',\'याज्ञवल्क्य\',\'वशिष्ठ\'],en:[\'Vishwamitra\',\'Uddalaka\',\'Yajnavalkya\',\'Vashistha\']},ans:2,exp:{hi:\'याज्ञवल्क्य ने "नेति नेति" (न यह, न यह) से परमात्मा को समझाया।\',en:\'Yajnavalkya used "Neti Neti" to describe Brahman by negation.\'}},\n  {q:{hi:\'आयुर्वेद की जड़ें किस वेद में हैं?\',en:\'Roots of Ayurveda are in which Veda?\'},opts:{hi:[\'ऋग्वेद\',\'सामवेद\',\'यजुर्वेद\',\'अथर्ववेद\'],en:[\'Rigveda\',\'Samaveda\',\'Yajurveda\',\'Atharvaveda\']},ans:3,exp:{hi:\'अथर्ववेद में जड़ी-बूटियों, बीमारियों के इलाज के मंत्र हैं।\',en:\'The Atharvaveda contains herbal remedies and healing spells — the foundation of Ayurveda.\'}},\n  {q:{hi:\'महात्मा गांधी का सबसे पसंदीदा उपनिषद?\',en:\'Gandhi\\\'s favorite Upanishad?\'},opts:{hi:[\'बृहदारण्यक\',\'छांदोग्य\',\'ईशावास्य\',\'माण्डूक्य\'],en:[\'Brihadaranyaka\',\'Chandogya\',\'Isha\',\'Mandukya\']},ans:2,exp:{hi:\'गांधीजी ने कहा — "अगर सिर्फ पहला श्लोक बचे, तो काफी है।"\',en:\'Gandhi said — "If only the first verse remained, it would be sufficient for all of humanity."\'}},\n  {q:{hi:\'सबसे बड़ा उपनिषद कौन सा है?\',en:\'Which is the largest Upanishad?\'},opts:{hi:[\'छांदोग्य\',\'बृहदारण्यक\',\'मुंडक\',\'कठ\'],en:[\'Chandogya\',\'Brihadaranyaka\',\'Mundaka\',\'Katha\']},ans:1,exp:{hi:\'बृहदारण्यक उपनिषद सबसे बड़ा है — याज्ञवल्क्य की शिक्षाएं और "अहम् ब्रह्मास्मि।"\',en:\'Brihadaranyaka is the largest — Yajnavalkya\\\'s teachings and "Aham Brahmasmi."\'}},\n  {q:{hi:\'भारतीय शास्त्रीय संगीत की जड़ें किस वेद में?\',en:\'Roots of Indian classical music are in which Veda?\'},opts:{hi:[\'ऋग्वेद\',\'सामवेद\',\'यजुर्वेद\',\'अथर्ववेद\'],en:[\'Rigveda\',\'Samaveda\',\'Yajurveda\',\'Atharvaveda\']},ans:1,exp:{hi:\'सामवेद में मंत्र राग में गाए जाते थे। सात स्वर यहीं से आए।\',en:\'Samaveda had mantras sung in melody. The seven musical notes (Sa Re Ga...) originated here.\'}},\n  {q:{hi:\'छांदोग्य उपनिषद में नमक-पानी का उदाहरण किसने दिया?\',en:\'Who gave the salt-water example in Chandogya?\'},opts:{hi:[\'याज्ञवल्क्य\',\'उद्दालक\',\'गार्गी\',\'विश्वामित्र\'],en:[\'Yajnavalkya\',\'Uddalaka\',\'Gargi\',\'Vishwamitra\']},ans:1,exp:{hi:\'उद्दालक आरुणि ने बेटे श्वेतकेतु को नमक-पानी से "तत् त्वम् असि" समझाया।\',en:\'Uddalaka Aruni explained "Tat tvam asi" to his son Shvetaketu using the salt dissolved in water.\'}},\n  {q:{hi:\'ॐ में "म" कौन सी अवस्था दर्शाता है?\',en:\'What state does "M" in Om represent?\'},opts:{hi:[\'जागृति\',\'स्वप्न\',\'सुषुप्ति (गहरी नींद)\',\'तुरीय\'],en:[\'Waking\',\'Dream\',\'Deep Sleep\',\'Turiya\']},ans:2,exp:{hi:\'अ = जागना, उ = सपना, म = गहरी नींद, मौन = तुरीय (शुद्ध चेतना)।\',en:\'A = Waking, U = Dream, M = Deep Sleep, Silence = Turiya (pure consciousness).\'}},\n];\n\n/* ────────── RENDER HOME ────────── */\nfunction renderHome(){\n  const dv=DAILY[new Date().getDate()%DAILY.length];\n  const v=VEDAS[activeVeda], sd=v.secD[activeSection];\n  const isUp=activeSection===3;\n  $(\'app\').innerHTML=`\n  <div class="search-wrap">\n    <span class="search-icon">🔍</span>\n    <input class="search-input" id="si" placeholder="${lang===\'hi\'?\'खोजें — उपनिषद, देवता, मंत्र...\':\'Search — Upanishads, deities, mantras...\'}" oninput="doSearch(this.value)" onblur="setTimeout(()=>{const e=$(\'sr\');if(e)e.style.display=\'none\'},200)">\n    <div class="search-results" id="sr"></div>\n  </div>\n\n  <div class="daily-banner card-enter">\n    <div class="daily-label"><div class="daily-dot"></div>${lang===\'hi\'?\'आज का श्लोक\':\'Verse of the Day\'}</div>\n    <div class="daily-shloka">${dv.s}</div>\n    <div class="daily-meaning">${L(dv.m)}</div>\n    <div class="daily-footer">\n      <div class="daily-source">${dv.src}</div>\n      <div class="daily-actions">\n        <button class="daily-btn" onclick="shareText(\'${dv.s.replace(/\\n/,\' \')} — \'+L({hi:\'${dv.m.hi.substring(0,60)}\',en:\'${(dv.m.en||dv.m.hi).substring(0,60)}\'}))">📱 ${lang===\'hi\'?\'शेयर\':\'Share\'}</button>\n      </div>\n    </div>\n  </div>\n\n  <div class="veda-tabs">\n    ${VEDAS.map((vv,i)=>`\n    <button class="tab-btn ${i===activeVeda?\'active\':\'\'}" onclick="setVeda(${i})" style="${i===activeVeda?`border-color:${vv.bd};border-width:2px`:``}">\n      <span class="tab-icon">${vv.icon}</span>\n      <div class="tab-name" style="${i===activeVeda?`color:${vv.c}`:\'\'}">${L(vv.name)}</div>\n      <div class="tab-sub">${L(vv.sub)}</div>\n      <div class="tab-bm">${bookmarks.includes(vv.id)?\'🔖\':\'\'} ${readProgress[vv.id]?\'✅\':\'\'}</div>\n    </button>`).join(\'\')}\n  </div>\n\n  <div class="progress-wrap">\n    <div class="progress-label"><span>${L(v.name)}</span><span style="color:${v.c}">${Math.round((activeVeda+1)/4*100)}%</span></div>\n    <div class="progress-bar"><div class="progress-fill" style="width:${(activeVeda+1)/4*100}%;background:linear-gradient(90deg,${v.c},${v.bd})"></div></div>\n  </div>\n\n  <div class="card card-enter">\n    <div class="card-header">\n      <div class="veda-emblem" style="background:${v.bg}">${v.icon}</div>\n      <div class="veda-meta" style="flex:1">\n        <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-bottom:5px">\n          <h2 style="color:${v.c}">${L(v.name)} <span style="font-size:13px;color:var(--muted);font-weight:400">— ${L(v.sub)}</span></h2>\n        </div>\n        <p>${L(v.p)}</p>\n        <div class="badges">${L(v.badges).map(b=>`<span class="badge" style="background:${v.bg};color:${v.c};border:1px solid ${v.bd}">${b}</span>`).join(\'\')}</div>\n        <div class="veda-actions">\n          <button class="icon-btn ${bookmarks.includes(v.id)?\'active\':\'\'}" onclick="toggleBM(\'${v.id}\')">${bookmarks.includes(v.id)?\'🔖 सेव है\':\'🏷 सेव करें\'}</button>\n          <button class="icon-btn ${readProgress[v.id]?\'active\':\'\'}" onclick="markRead(\'${v.id}\')">${readProgress[v.id]?\'✅ पढ़ा\':\'📖 पढ़ा माना\'}</button>\n          <button class="icon-btn" onclick="shareText(\'${L(v.name)}: ${L(v.p).substring(0,100)}...\')">📤 ${lang===\'hi\'?\'शेयर\':\'Share\'}</button>\n        </div>\n      </div>\n    </div>\n\n    <div class="facts-row">\n      ${v.facts.map(f=>`<div class="fact-box" style="background:${v.bg}"><div class="fact-num" style="color:${v.c}">${f.n}</div><div class="fact-label">${L(f.l)}</div></div>`).join(\'\')}\n    </div>\n\n    <div class="nav-row2">\n      <div class="section-label">${lang===\'hi\'?\'खंड चुनें\':\'Choose Section\'}</div>\n      <div class="dots">${v.secs.map((_,i)=>`<div class="dot ${i===activeSection?\'active\':\'\'}" style="${i===activeSection?`background:${v.c}`:\'\'}" onclick="setSec(${i})"></div>`).join(\'\')}</div>\n    </div>\n    <div class="section-grid">\n      ${v.secs.map((s,i)=>`<div class="sec-card ${i===activeSection?\'active\':\'\'}" onclick="setSec(${i})" style="${i===activeSection?`border-color:${v.c};background:${v.bg}`:\'\'}">\n        <div class="sec-card-icon">${s.i}</div>\n        <div class="sec-card-name" style="${i===activeSection?`color:${v.c}`:\'\'}"> ${L(s.n)}</div>\n        <div class="sec-card-sub">${L(s.s)}</div>\n      </div>`).join(\'\')}\n    </div>\n\n    <div class="detail-box" style="border-left-color:${v.c}">\n      <h3>${L(sd.t)}</h3>\n      <p>${L(sd.d)}</p>\n    </div>\n\n    ${isUp?`\n    <div style="margin-top:14px">\n      <div class="section-label" style="margin-bottom:10px">${lang===\'hi\'?\'उपनिषद चुनें\':\'Choose Upanishad\'}</div>\n      <div style="display:grid;grid-template-columns:repeat(2,1fr);gap:8px">\n        ${UPANISHADS.filter(u=>u.vedaId===v.id).map((u,i)=>{\n          const gIdx=UPANISHADS.indexOf(u);\n          return `<div class="up-card ${activeUpanishad===gIdx?\'active\':\'\'}" onclick="setUpIdx(${gIdx})" style="${activeUpanishad===gIdx?`border-color:${v.c};background:${v.bg}`:\'\'}">\n            <div class="up-card-top">\n              <div class="up-card-name" style="${activeUpanishad===gIdx?`color:${v.c}`:\'\'}"> ${L(u.name)}</div>\n              <span class="up-card-veda" style="background:${v.bg};color:${v.c}">${L(u.level)}</span>\n            </div>\n            <div class="up-card-sub">${u.chapters[lang||\'hi\']} • ${u.verses[lang||\'hi\']}</div>\n            <div class="up-card-teaser">${L(u.teaser)}</div>\n            <div class="up-card-mv" style="background:${v.bg};color:${v.c}">${u.mv}</div>\n          </div>`;\n        }).join(\'\')}\n      </div>\n      ${activeUpanishad!==null&&UPANISHADS[activeUpanishad]&&UPANISHADS[activeUpanishad].vedaId===v.id?renderUpDeep(UPANISHADS[activeUpanishad],v.c):\'\'}\n    </div>`:``}\n  </div>\n\n  <div class="card card-enter">\n    <div class="section-label" style="margin-bottom:10px">${L(v.name)} — ${lang===\'hi\'?\'एक ऋचा\':\'A Verse\'}</div>\n    <div class="hymn-box" style="background:${v.bg};border-color:${v.bd}">\n      <div class="hymn-sanskrit">${v.hymn.s}</div>\n      <div class="hymn-divider" style="background:${v.bd}"></div>\n      <div class="hymn-arth">${L(v.hymn.a)}</div>\n      <div class="hymn-src">${v.hymn.src}</div>\n      <button class="hymn-share" onclick="shareText(\'${v.hymn.s.replace(/\\n/,\' \')}\')">📤</button>\n    </div>\n  </div>\n\n  <div class="card card-enter">\n    <div class="section-label" style="margin-bottom:12px">${lang===\'hi\'?\'मुख्य बातें — टैप करें\':\'Key Concepts — Tap to learn\'}</div>\n    <div class="concept-chips">\n      ${L(v.concepts).map((c,i)=>{const k=v.concepts.hi[i];return`<span class="chip ${activeConcept===k?\'active\':\'\'}" onclick="setConcept(\'${k}\')" style="${activeConcept===k?`background:${v.bg};color:${v.c};border-color:${v.c}`:\'\'}"> ${c}</span>`}).join(\'\')}\n    </div>\n    ${activeConcept&&v.ci[activeConcept]?`<div class="detail-box" style="border-left-color:${v.c};margin-top:4px"><h3>${activeConcept}</h3><p>${L(v.ci[activeConcept])}</p></div>`:`<p style="font-size:12px;color:var(--muted);font-style:italic">${lang===\'hi\'?\'किसी बात पर टैप करें।\':\'Tap a concept to learn more.\'}</p>`}\n  </div>\n\n  <div class="card card-enter">\n    <div class="section-label" style="margin-bottom:8px">📝 ${lang===\'hi\'?\'मेरे नोट्स\':\'My Notes\'}</div>\n    <textarea class="notes-textarea" id="note_${v.id}" placeholder="${lang===\'hi\'?`${L(v.name)} के बारे में अपने विचार लिखें...`:`Write your thoughts about ${L(v.name)}...`}">${notes[v.id]||\'\'}</textarea>\n    <div class="notes-actions">\n      <button class="notes-save" onclick="saveNote(\'${v.id}\')" style="background:${v.c}">${lang===\'hi\'?\'💾 नोट सेव करें\':\'💾 Save Note\'}</button>\n      <span class="notes-saved" id="note_saved_${v.id}">✅ ${lang===\'hi\'?\'सेव हो गया!\':\'Saved!\'}</span>\n    </div>\n  </div>\n\n  <button class="ask-btn" style="border-color:${v.c};color:${v.c};background:${v.bg}" onclick="window.open(\'https://claude.ai\',\'_blank\')">${lang===\'hi\'?`${L(v.name)} के बारे में और जानें — Claude से पूछें ↗`:`Learn more about ${L(v.name)} — Ask Claude ↗`}</button>`;\n  buildSearch();\n}\n\nfunction renderUpDeep(u,color){\n  const tabs=[{k:\'story\',l:{hi:\'कहानी\',en:\'Story\'}},{k:\'lessons\',l:{hi:\'सीख\',en:\'Lessons\'}},{k:\'verse\',l:{hi:\'श्लोक\',en:\'Verse\'}},{k:\'notes\',l:{hi:\'नोट्स\',en:\'Notes\'}}];\n  let content=\'\';\n  if(activeUpTab===\'story\'){\n    content=`<div class="up-story">${L(u.story).replace(/\\n\\n/g,\'</div><div class="up-story">\').replace(/\\n/g,\'<br>\')}</div>`;\n  }else if(activeUpTab===\'lessons\'){\n    content=`<div class="up-lesson-grid">${u.lessons.map(l=>`<div class="up-lesson" style="border-left-color:${color}"><div class="up-lesson-icon">${l.icon}</div><div class="up-lesson-title">${L(l.t)}</div><div class="up-lesson-text">${L(l.d)}</div></div>`).join(\'\')}</div>`;\n  }else if(activeUpTab===\'verse\'){\n    content=`<div class="up-verse-box"><div class="up-verse-sanskrit">${u.verse.s}</div><div class="up-verse-divider"></div><div class="up-verse-arth">${L(u.verse.a)}</div><div class="up-verse-src">${u.verse.src}</div></div>`;\n  }else if(activeUpTab===\'notes\'){\n    content=`<div class="notes-wrap"><textarea class="notes-textarea" id="note_up_${u.id}" placeholder="${lang===\'hi\'?`${L(u.name)} के बारे में नोट्स...`:`Notes on ${L(u.name)}...`}">${notes[\'up_\'+u.id]||\'\'}</textarea><div class="notes-actions"><button class="notes-save" onclick="saveNote(\'up_${u.id}\')" style="background:${color}">${lang===\'hi\'?\'💾 सेव करें\':\'💾 Save\'}</button><span class="notes-saved" id="note_saved_up_${u.id}">✅</span></div></div>`;\n  }\n  return `\n  <div class="up-deep" style="margin-top:14px">\n    <div class="up-deep-header">\n      <div class="up-mv-box">\n        <div class="up-mv-sanskrit">${u.mv}</div>\n        <div class="up-mv-trans">${L(u.mv_arth)}</div>\n        <div class="up-mv-source">${L(u.name)} — ${L(u.veda)}</div>\n      </div>\n      <div class="up-deep-meta" style="margin-top:10px">\n        <span>📖 ${L(u.chapters)}</span>\n        <span>📝 ${L(u.verses)}</span>\n        <span>⭐ ${L(u.level)}</span>\n        <span style="cursor:pointer" onclick="toggleBM(\'up_${u.id}\')">${bookmarks.includes(\'up_\'+u.id)?\'🔖 Saved\':\'🏷 Save\'}</span>\n      </div>\n    </div>\n    <div class="up-tabs">\n      ${tabs.map(t=>`<button class="up-tab ${activeUpTab===t.k?\'active\':\'\'}" onclick="setUpTab(\'${t.k}\')">${L(t.l)}</button>`).join(\'\')}\n    </div>\n    <div class="up-content">${content}</div>\n  </div>`;\n}\n\n/* ────────── RENDER UPANISHADS PAGE ────────── */\nfunction renderUpanishads(){\n  const filters=[{k:\'all\',l:{hi:\'सभी\',en:\'All\'}},{k:\'rig\',l:{hi:\'ऋग्वेद\',en:\'Rigveda\'}},{k:\'sama\',l:{hi:\'सामवेद\',en:\'Samaveda\'}},{k:\'yajur\',l:{hi:\'यजुर्वेद\',en:\'Yajurveda\'}},{k:\'atharva\',l:{hi:\'अथर्ववेद\',en:\'Atharvaveda\'}},{k:\'beginner\',l:{hi:\'शुरुआती\',en:\'Beginner\'}},{k:\'advanced\',l:{hi:\'उन्नत\',en:\'Advanced\'}}];\n  const filtered=activeUpFilter===\'all\'?UPANISHADS:activeUpFilter===\'beginner\'?UPANISHADS.filter(u=>u.level.hi===\'शुरुआती\'):activeUpFilter===\'advanced\'?UPANISHADS.filter(u=>u.level.hi===\'उन्नत\'):UPANISHADS.filter(u=>u.vedaId===activeUpFilter);\n  $(\'app\').innerHTML=`\n  <div class="up-hero">\n    <h2>🧘 ${lang===\'hi\'?\'उपनिषद — ज्ञान का सागर\':\'Upanishads — Ocean of Wisdom\'}</h2>\n    <p>${lang===\'hi\'?\'उपनिषद माने "पास बैठना" — गुरु के पास बैठकर ज्ञान पाना। वेदों का दार्शनिक भाग। इनमें आत्मा, परमात्मा और मोक्ष के सवालों के जवाब हैं।\':\'Upanishad means "sitting close" — gaining wisdom by sitting near the teacher. The philosophical layer of the Vedas. They answer questions about the Self, God and liberation.\'}</p>\n    <div class="up-stats">\n      <div class="up-stat"><div class="up-stat-num">108</div><div class="up-stat-label">${lang===\'hi\'?\'कुल उपनिषद\':\'Total Upanishads\'}</div></div>\n      <div class="up-stat"><div class="up-stat-num">10</div><div class="up-stat-label">${lang===\'hi\'?\'मुख्य (दशोपनिषद)\':\'Principal (Dasopanishad)\'}</div></div>\n      <div class="up-stat"><div class="up-stat-num">4</div><div class="up-stat-label">${lang===\'hi\'?\'महावाक्य\':\'Mahavakyas\'}</div></div>\n      <div class="up-stat"><div class="up-stat-num">~800</div><div class="up-stat-label">${lang===\'hi\'?\'ईसा पूर्व (BCE)\':\'BCE composed\'}</div></div>\n    </div>\n  </div>\n\n  <div class="up-filter">\n    ${filters.map(f=>`<button class="up-filter-btn ${activeUpFilter===f.k?\'active\':\'\'}" onclick="setUpFilter(\'${f.k}\')" style="${activeUpFilter===f.k?`background:var(--s);color:#fff`:\'\'}">${L(f.l)}</button>`).join(\'\')}\n  </div>\n\n  <div class="up-grid">\n    ${filtered.map(u=>`\n    <div class="up-card ${activeUpanishad===UPANISHADS.indexOf(u)?\'active\':\'\'}" onclick="setUpIdx(${UPANISHADS.indexOf(u)})" style="${activeUpanishad===UPANISHADS.indexOf(u)?`border-color:${u.vedaColor};`:\'\'}">\n      <div class="up-card-top">\n        <div class="up-card-name" style="${activeUpanishad===UPANISHADS.indexOf(u)?`color:${u.vedaColor}`:\'\'}"> ${L(u.name)}</div>\n        <span class="up-card-veda" style="background:${u.vedaColor}22;color:${u.vedaColor}">${L(u.veda)}</span>\n      </div>\n      <div class="up-card-sub">${L(u.chapters)} • ${L(u.verses)} • ${L(u.level)}</div>\n      <div class="up-card-teaser">${L(u.teaser)}</div>\n      <div class="up-card-mv" style="background:${u.vedaColor}15;color:${u.vedaColor}">${u.mv}</div>\n      <div class="up-card-badges">\n        ${L(u.tags).map(tg=>`<span class="up-mini-badge" style="background:${u.vedaColor}15;color:${u.vedaColor}">${tg}</span>`).join(\'\')}\n        ${bookmarks.includes(\'up_\'+u.id)?\'<span class="up-mini-badge" style="background:#F3F4F6;color:#666">🔖</span>\':\'\'}\n        ${readProgress[\'up_\'+u.id]?\'<span class="up-mini-badge" style="background:#E8F5E9;color:#2E7D32">✅ पढ़ा</span>\':\'\'}\n      </div>\n    </div>`).join(\'\')}\n  </div>\n\n  ${activeUpanishad!==null&&UPANISHADS[activeUpanishad]?`\n  <div class="up-deep">\n    <div class="up-deep-header">\n      <div class="up-deep-title" style="color:${UPANISHADS[activeUpanishad].vedaColor}">${L(UPANISHADS[activeUpanishad].name)}</div>\n      <div class="up-deep-meta">\n        <span>📖 ${L(UPANISHADS[activeUpanishad].chapters)}</span>\n        <span>📝 ${L(UPANISHADS[activeUpanishad].verses)}</span>\n        <span>⭐ ${L(UPANISHADS[activeUpanishad].level)}</span>\n        <span>${L(UPANISHADS[activeUpanishad].veda)}</span>\n        <span style="cursor:pointer;color:var(--s)" onclick="toggleBM(\'up_${UPANISHADS[activeUpanishad].id}\')">${bookmarks.includes(\'up_\'+UPANISHADS[activeUpanishad].id)?\'🔖 Saved\':\'🏷 Save\'}</span>\n        <span style="cursor:pointer;color:var(--g)" onclick="markRead(\'up_${UPANISHADS[activeUpanishad].id}\')">${readProgress[\'up_\'+UPANISHADS[activeUpanishad].id]?\'✅ Read\':\'📖 Mark read\'}</span>\n      </div>\n      <div class="up-mv-box" style="margin-top:12px">\n        <div class="up-mv-sanskrit">${UPANISHADS[activeUpanishad].mv}</div>\n        <div class="up-mv-trans">${L(UPANISHADS[activeUpanishad].mv_arth)}</div>\n      </div>\n    </div>\n    <div class="up-tabs">\n      ${[{k:\'story\',l:{hi:\'कहानी / शिक्षा\',en:\'Story / Teaching\'}},{k:\'lessons\',l:{hi:\'मुख्य सीख\',en:\'Key Lessons\'}},{k:\'verse\',l:{hi:\'प्रमुख श्लोक\',en:\'Key Verse\'}},{k:\'notes\',l:{hi:\'📝 नोट्स\',en:\'📝 Notes\'}}].map(t=>`<button class="up-tab ${activeUpTab===t.k?\'active\':\'\'}" onclick="setUpTab(\'${t.k}\')">${L(t.l)}</button>`).join(\'\')}\n    </div>\n    <div class="up-content">${getUpContent(UPANISHADS[activeUpanishad])}</div>\n  </div>`:\'\'}\n\n  <div class="card">\n    <h3 style="font-size:15px;font-weight:700;margin-bottom:14px">✨ ${lang===\'hi\'?\'4 महावाक्य\':\'4 Great Sayings (Mahavakyas)\'}</h3>\n    <div class="mv-grid">\n      ${[[\'प्रज्ञानम् ब्रह्म\',\'Consciousness is Brahman\',\'ऐतरेय उपनिषद\',\'Aitareya Upanishad\'],\n         [\'अहम् ब्रह्मास्मि\',\'I am Brahman\',\'बृहदारण्यक उपनिषद\',\'Brihadaranyaka Upanishad\'],\n         [\'तत् त्वम् असि\',\'That thou art\',\'छांदोग्य उपनिषद\',\'Chandogya Upanishad\'],\n         [\'अयम् आत्मा ब्रह्म\',\'This Self is Brahman\',\'माण्डूक्य उपनिषद\',\'Mandukya Upanishad\']\n      ].map(m=>`<div class="mv-card" onclick="shareText(\'${m[0]} — ${m[1]}\')">\n        <div class="mv-sanskrit">${m[0]}</div>\n        <div class="mv-trans">${lang===\'hi\'?\'"\'+m[0]+\'"\':\'"\'+m[1]+\'"\'}</div>\n        <div class="mv-source">${lang===\'hi\'?m[2]:m[3]}</div>\n      </div>`).join(\'\')}\n    </div>\n  </div>`;\n}\n\nfunction getUpContent(u){\n  if(activeUpTab===\'story\') return `<div class="up-story">${L(u.story).replace(/\\n\\n/g,\'</div><div class="up-story">\').replace(/\\n/g,\'<br>\')}</div>`;\n  if(activeUpTab===\'lessons\') return `<div class="up-lesson-grid">${u.lessons.map(l=>`<div class="up-lesson" style="border-left-color:${u.vedaColor}"><div class="up-lesson-icon">${l.icon}</div><div class="up-lesson-title">${L(l.t)}</div><div class="up-lesson-text">${L(l.d)}</div></div>`).join(\'\')}</div>`;\n  if(activeUpTab===\'verse\') return `<div class="up-verse-box"><div class="up-verse-sanskrit">${u.verse.s}</div><div class="up-verse-divider"></div><div class="up-verse-arth">${L(u.verse.a)}</div><div class="up-verse-src">${u.verse.src}</div></div><button class="daily-btn" style="margin-top:10px" onclick="shareText(\'${u.verse.s.replace(/\\n/,\' \')}\')">📱 ${lang===\'hi\'?\'शेयर\':\'Share\'}</button>`;\n  if(activeUpTab===\'notes\') return `<div class="notes-wrap"><textarea class="notes-textarea" id="note_up_${u.id}" placeholder="${lang===\'hi\'?`${L(u.name)} के बारे में नोट्स...`:`Notes on ${L(u.name)}...`}">${notes[\'up_\'+u.id]||\'\'}</textarea><div class="notes-actions"><button class="notes-save" onclick="saveNote(\'up_${u.id}\')" style="background:${u.vedaColor}">${lang===\'hi\'?\'💾 सेव करें\':\'💾 Save\'}</button><span class="notes-saved" id="note_saved_up_${u.id}">✅</span></div></div>`;\n  return \'\';\n}\n\n/* ────────── MAHAVAKYA PAGE ────────── */\nfunction renderMahavakya(){\n  $(\'app\').innerHTML=`\n  <div class="card card-enter">\n    <h2 style="font-size:18px;font-weight:700;margin-bottom:6px">✨ ${lang===\'hi\'?\'महावाक्य — महान वाक्य\':\'Mahavakyas — Great Sayings\'}</h2>\n    <p style="font-size:13px;color:var(--muted);margin-bottom:20px;line-height:1.75">${lang===\'hi\'?\'वेदांत के 4 सबसे महान वाक्य — जो आत्मा और परमात्मा की एकता बताते हैं। हर उपनिषद का मुख्य सन्देश।\':\'The 4 greatest statements of Vedanta — declaring the unity of Self and Brahman. The core message of each Veda.\'}</p>\n    ${[{mv:\'प्रज्ञानम् ब्रह्म\',en:\'Consciousness is Brahman\',src:{hi:\'ऐतरेय उपनिषद — ऋग्वेद\',en:\'Aitareya Upanishad — Rigveda\'},exp:{hi:\'जो देखने की, सुनने की, सोचने की शक्ति है — वही ब्रह्म है। चेतना ही परमात्मा है। हम हर पल इसे महसूस कर रहे हैं।\',en:\'The power of seeing, hearing, thinking — that IS Brahman. Consciousness is God. We experience it every moment.\'},c:\'#BA7517\'},\n       {mv:\'अहम् ब्रह्मास्मि\',en:\'I am Brahman\',src:{hi:\'बृहदारण्यक उपनिषद — यजुर्वेद\',en:\'Brihadaranyaka Upanishad — Yajurveda\'},exp:{hi:\'याज्ञवल्क्य की शिक्षा। मैं कोई छोटा शरीर नहीं हूं — मैं अनंत ब्रह्म हूं। यह घमंड नहीं, यह सत्य है।\',en:\'Yajnavalkya\\\'s teaching. I am not a small body — I am infinite Brahman. Not arrogance — this is truth.\'},c:\'#3B6D11\'},\n       {mv:\'तत् त्वम् असि\',en:\'That thou art\',src:{hi:\'छांदोग्य उपनिषद — सामवेद\',en:\'Chandogya Upanishad — Samaveda\'},exp:{hi:\'उद्दालक ने बेटे श्वेतकेतु को कहा — "वह परमात्मा जो हर जगह है, वह तुम हो।" यह सबसे सरल और सबसे गहरी बात है।\',en:\'Uddalaka told his son Shvetaketu — "That God who is everywhere, that is you." The simplest and deepest truth.\'},c:\'#185FA5\'},\n       {mv:\'अयम् आत्मा ब्रह्म\',en:\'This Self is Brahman\',src:{hi:\'माण्डूक्य उपनिषद — अथर्ववेद\',en:\'Mandukya Upanishad — Atharvaveda\'},exp:{hi:\'तुम्हारे अंदर जो आत्मा है और बाहर जो ब्रह्मांड है — दोनों एक ही हैं। यह अनुभव होना ही मोक्ष है।\',en:\'The Self within you and the universe outside — they are one. Experiencing this unity is liberation.\'},c:\'#534AB7\'},\n    ].map(m=>`\n    <div style="background:linear-gradient(135deg,#1C0A02,#3D1A05);border-radius:var(--r);padding:1.4rem;margin-bottom:1rem;border:1px solid rgba(200,144,10,.3);box-shadow:var(--shadow-lg)">\n      <div style="display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:8px;margin-bottom:12px">\n        <div style="font-family:\'Tiro Devanagari Sanskrit\',serif;font-size:22px;color:#FFD700;line-height:1.5">${m.mv}</div>\n        <span style="background:rgba(255,255,255,.08);color:#FFE8C0;padding:4px 12px;border-radius:20px;font-size:12px;font-style:italic">${lang===\'hi\'?\'"\'+m.mv+\'"\':\'"\'+m.en+\'"\'}</span>\n      </div>\n      <div style="font-size:11px;color:rgba(255,215,0,.6);margin-bottom:10px;font-style:italic">${L(m.src)}</div>\n      <div style="font-size:13px;color:rgba(255,255,255,.78);line-height:1.85;margin-bottom:12px">${L(m.exp)}</div>\n      <button class="daily-btn" onclick="shareText(\'${m.mv} — ${m.en}\')">📱 ${lang===\'hi\'?\'शेयर करें\':\'Share\'}</button>\n    </div>`).join(\'\')}\n  </div>`;\n}\n\n/* ────────── RISHIS ────────── */\nfunction renderRishis(){\n  $(\'app\').innerHTML=`<div class="card card-enter">\n    <h2 style="font-size:17px;font-weight:700;margin-bottom:4px">🙏 ${lang===\'hi\'?\'वैदिक ऋषि\':\'Vedic Sages\'}</h2>\n    <p style="font-size:13px;color:var(--muted);margin-bottom:16px;line-height:1.7">${lang===\'hi\'?\'जिन्होंने वेदों और उपनिषदों की रचना की — और हमें जीवन की सबसे बड़ी सच्चाइयां सिखाईं।\':\'Those who composed the Vedas and Upanishads — and taught us life\\\'s greatest truths.\'}</p>\n    <div class="rishi-grid">${RISHIS.map((r,i)=>`<div class="rishi-card ${activeRishi===i?\'active\':\'\'}" onclick="setRishi(${i})"><div class="rishi-icon">${r.icon}</div><div class="rishi-name">${L(r.name)}</div><div class="rishi-veda">${L(r.veda)}</div></div>`).join(\'\')}</div>\n    ${activeRishi!==null?`<div class="rishi-detail"><h4>${RISHIS[activeRishi].icon} ${L(RISHIS[activeRishi].name)}</h4><p>${L(RISHIS[activeRishi].d)}</p></div>`:`<p style="font-size:12px;color:var(--muted);margin-top:14px;font-style:italic">${lang===\'hi\'?\'किसी ऋषि पर टैप करें।\':\'Tap a sage to learn about them.\'}</p>`}\n  </div>`;\n}\n\n/* ────────── DEITIES ────────── */\nfunction renderDeities(){\n  $(\'app\').innerHTML=`<div class="card card-enter">\n    <h2 style="font-size:17px;font-weight:700;margin-bottom:4px">⚡ ${lang===\'hi\'?\'वैदिक देवता\':\'Vedic Deities\'}</h2>\n    <p style="font-size:13px;color:var(--muted);margin-bottom:16px">${lang===\'hi\'?\'ऋग्वेद के मुख्य देव\':\'Main gods of the Rigveda\'}</p>\n    <div class="deity-grid">${DEITIES.map((d,i)=>`<div class="deity-card ${activeDeity===i?\'active\':\'\'}" onclick="setDeity(${i})">\n      <div class="deity-svg"><svg viewBox="0 0 54 54" xmlns="http://www.w3.org/2000/svg"><circle cx="27" cy="27" r="25" fill="${d.c}22" stroke="${d.c}" stroke-width="1.5"/><text x="27" y="35" text-anchor="middle" font-size="24">${d.icon}</text></svg></div>\n      <div class="deity-name" style="${activeDeity===i?`color:${d.c}`:\'\'}"> ${L(d.name)}</div>\n      <div class="deity-role">${L(d.role)}</div>\n    </div>`).join(\'\')}</div>\n    ${activeDeity!==null?`<div class="deity-detail" style="border-left-color:${DEITIES[activeDeity].c}"><h4>${DEITIES[activeDeity].icon} ${L(DEITIES[activeDeity].name)} — ${L(DEITIES[activeDeity].role)}</h4><p>${L(DEITIES[activeDeity].d)}</p></div>`:`<p style="font-size:12px;color:var(--muted);margin-top:14px;font-style:italic">${lang===\'hi\'?\'किसी देव पर टैप करें।\':\'Tap a deity to learn.\'}</p>`}\n  </div>`;\n}\n\n/* ────────── TIMELINE ────────── */\nfunction renderTimeline(){\n  const items=[\n    {y:\'~1500 BCE\',t:{hi:\'ऋग्वेद की रचना\',en:\'Rigveda Composed\'},d:{hi:\'सबसे पुराना वेद। अग्नि, इंद्र, वरुण की स्तुतियां। गायत्री मंत्र।\',en:\'Oldest Veda. Hymns to Agni, Indra, Varuna. The Gayatri Mantra.\'},c:\'#E8621A\'},\n    {y:\'~1200 BCE\',t:{hi:\'सामवेद और यजुर्वेद\',en:\'Samaveda & Yajurveda\'},d:{hi:\'संगीत वेद और यज्ञ विधि वेद। भारतीय शास्त्रीय संगीत का जन्म।\',en:\'Veda of Music and Veda of Ritual. Birth of Indian classical music.\'},c:\'#185FA5\'},\n    {y:\'~1000 BCE\',t:{hi:\'अथर्ववेद\',en:\'Atharvaveda\'},d:{hi:\'चौथा वेद। जड़ी-बूटी, इलाज, दैनिक जीवन। आयुर्वेद की नींव।\',en:\'Fourth Veda. Medicine, healing, everyday life. Foundation of Ayurveda.\'},c:\'#534AB7\'},\n    {y:\'~700 BCE\',t:{hi:\'प्रारंभिक उपनिषद\',en:\'Early Upanishads\'},d:{hi:\'बृहदारण्यक, छांदोग्य। याज्ञवल्क्य, गार्गी, उद्दालक का काल।\',en:\'Brihadaranyaka, Chandogya. Era of Yajnavalkya, Gargi, Uddalaka.\'},c:\'#7C3AED\'},\n    {y:\'~500 BCE\',t:{hi:\'बाद के उपनिषद\',en:\'Later Upanishads\'},d:{hi:\'कठ, मुंडक, माण्डूक्य, ईशावास्य। बौद्ध और जैन धर्म का उदय भी।\',en:\'Katha, Mundaka, Mandukya, Isha. Buddhism and Jainism also emerge.\'},c:\'#DB2777\'},\n    {y:\'~200 BCE\',t:{hi:\'भगवद्गीता\',en:\'Bhagavad Gita\'},d:{hi:\'वेदों और उपनिषदों का सार। "योगः कर्मसु कौशलम्।"\',en:\'Essence of Vedas and Upanishads. "Yoga is excellence in action."\'},c:\'#059669\'},\n    {y:\'~800 CE\',t:{hi:\'आदि शंकराचार्य\',en:\'Adi Shankaracharya\'},d:{hi:\'अद्वैत वेदांत। उपनिषदों की व्याख्या। "माण्डूक्य अकेला काफी है।"\',en:\'Advaita Vedanta. Commentaries on Upanishads. "Mandukya alone is sufficient."\'},c:\'#D97706\'},\n  ];\n  $(\'app\').innerHTML=`<div class="card card-enter">\n    <h2 style="font-size:17px;font-weight:700;margin-bottom:4px">📅 ${lang===\'hi\'?\'वैदिक काल-रेखा\':\'Vedic Timeline\'}</h2>\n    <p style="font-size:13px;color:var(--muted);margin-bottom:20px">${lang===\'hi\'?\'वेदों का इतिहास — कब क्या हुआ\':\'History of the Vedas\'}</p>\n    <div class="timeline">${items.map(it=>`<div class="tl-item"><div class="tl-dot" style="background:${it.c}"></div><div class="tl-year" style="color:${it.c}">${it.y}</div><div class="tl-title">${L(it.t)}</div><div class="tl-desc">${L(it.d)}</div></div>`).join(\'\')}</div>\n  </div>`;\n}\n\n/* ────────── QUIZ ────────── */\nfunction renderQuiz(){\n  const q=QUIZ[quizState.idx];\n  if(quizState.done){\n    const pct=Math.round(quizState.score/QUIZ.length*100);\n    $(\'app\').innerHTML=`<div class="quiz-wrap"><div class="quiz-card"><div class="qz-result">\n      <div style="font-size:36px;margin-bottom:12px">${pct>=80?\'🏆\':pct>=50?\'👍\':\'📖\'}</div>\n      <div class="qz-result-num">${quizState.score}/${QUIZ.length}</div>\n      <div class="qz-result-msg">${lang===\'hi\'?(pct>=80?\'शाबाश! आप वेद विशेषज्ञ हैं 🎉\':pct>=50?\'अच्छा प्रयास! और पढ़ें 📚\':\'फिर कोशिश करें! वेद पढ़ें 🙏\'):(pct>=80?\'Excellent! You are a Veda expert 🎉\':pct>=50?\'Good effort! Read more 📚\':\'Try again! Study the Vedas 🙏\')}</div>\n      <div style="margin:16px 0;padding:16px;background:var(--cream);border-radius:var(--rs);text-align:left">\n        ${QUIZ.map((q,i)=>`<div style="font-size:12px;padding:4px 0;color:var(--soft)">${i+1}. ${L(q.q)} — <span style="color:var(--s);font-weight:700">${L(q.opts)[q.ans]}</span></div>`).join(\'\')}\n      </div>\n      <button class="qz-restart" onclick="quizState={idx:0,score:0,answered:false,sel:null,done:false};renderQuiz()">${lang===\'hi\'?\'🔄 फिर खेलें\':\'🔄 Play Again\'}</button>\n    </div></div></div>`;\n    return;\n  }\n  $(\'app\').innerHTML=`<div class="quiz-wrap"><div class="quiz-card">\n    <div class="qz-top">\n      <span class="qz-q-num">${lang===\'hi\'?\'सवाल\':\'Question\'} ${quizState.idx+1} / ${QUIZ.length}</span>\n      <span class="qz-score-badge">${lang===\'hi\'?\'स्कोर\':\'Score\'}: ${quizState.score}</span>\n    </div>\n    <div class="qz-bar"><div class="qz-bar-fill" style="width:${quizState.idx/QUIZ.length*100}%"></div></div>\n    ${q.shloka?`<div class="qz-shloka">${q.shloka}</div>`:\'\'}\n    <div class="qz-q">${L(q.q)}</div>\n    <div class="qz-opts">\n      ${L(q.opts).map((opt,i)=>{\n        let cls=\'qz-opt\';\n        if(quizState.answered){cls+=i===q.ans?\' correct\':i===quizState.sel?\' wrong\':\'\';}\n        return`<button class="${cls}" ${quizState.answered?\'disabled\':\'\'} onclick="answerQ(${i})">${opt}</button>`;\n      }).join(\'\')}\n    </div>\n    ${quizState.answered?`<div class="qz-fb ${quizState.sel===q.ans?\'correct\':\'wrong\'}">${quizState.sel===q.ans?\'✅ \'+( lang===\'hi\'?\'सही जवाब!\':\'Correct!\'):\'❌ \'+(lang===\'hi\'?\'गलत।\':\'Wrong.\')} — ${L(q.exp)}</div><button class="qz-next" onclick="nextQ()">${quizState.idx===QUIZ.length-1?(lang===\'hi\'?\'नतीजा देखें →\':\'See Result →\'):(lang===\'hi\'?\'अगला सवाल →\':\'Next Question →\')}</button>`:\'\'}\n  </div></div>`;\n}\nfunction answerQ(i){if(quizState.answered)return;quizState.answered=true;quizState.sel=i;if(i===QUIZ[quizState.idx].ans)quizState.score++;renderQuiz()}\nfunction nextQ(){quizState.idx++;if(quizState.idx>=QUIZ.length)quizState.done=true;else{quizState.answered=false;quizState.sel=null;}renderQuiz()}\n\n/* ────────── PROGRESS ────────── */\nfunction renderProgress(){\n  const totalItems=[...VEDAS.map(v=>v.id),...UPANISHADS.map(u=>\'up_\'+u.id)];\n  const done=totalItems.filter(k=>readProgress[k]).length;\n  const pct=Math.round(done/totalItems.length*100);\n  $(\'app\').innerHTML=`\n  <div class="progress-tracker card-enter">\n    <div class="pt-title">📈 ${lang===\'hi\'?\'मेरी पढ़ाई की प्रगति\':\'My Learning Progress\'}\n      <span style="font-size:12px;color:var(--muted);font-weight:400">${done}/${totalItems.length} ${lang===\'hi\'?\'पढ़े\':\'read\'}</span>\n    </div>\n    <div class="pt-bar-wrap"><div class="pt-bar" style="width:${pct}%"></div></div>\n    <div class="pt-percent">${pct}% ${lang===\'hi\'?\'पूरा हुआ\':\'complete\'}</div>\n  </div>\n\n  <div class="card card-enter">\n    <h3 style="font-size:15px;font-weight:700;margin-bottom:14px">📚 ${lang===\'hi\'?\'वेद\':\'Vedas\'}</h3>\n    <div class="pt-grid">\n      ${VEDAS.map(v=>`<div class="pt-item ${readProgress[v.id]?\'done\':\'\'}" onclick="readProgress[\'${v.id}\']=!readProgress[\'${v.id}\'];save(\'vg_prog\',readProgress);renderProgress()">\n        <div class="pt-icon">${v.icon}</div>\n        <div class="pt-name">${L(v.name)}</div>\n        <div class="pt-status">${readProgress[v.id]?\'✅ पढ़ा\':\'○ बाकी\'}</div>\n      </div>`).join(\'\')}\n    </div>\n  </div>\n\n  <div class="card card-enter">\n    <h3 style="font-size:15px;font-weight:700;margin-bottom:14px">🧘 ${lang===\'hi\'?\'उपनिषद\':\'Upanishads\'}</h3>\n    <div class="pt-grid">\n      ${UPANISHADS.map(u=>`<div class="pt-item ${readProgress[\'up_\'+u.id]?\'done\':\'\'}" onclick="readProgress[\'up_${u.id}\']=!readProgress[\'up_${u.id}\'];save(\'vg_prog\',readProgress);renderProgress()">\n        <div class="pt-icon" style="font-size:14px;color:${u.vedaColor}">${L(u.name).split(\' \')[0]}</div>\n        <div class="pt-status">${readProgress[\'up_\'+u.id]?\'✅\':\'○\'}</div>\n      </div>`).join(\'\')}\n    </div>\n  </div>\n\n  <div class="card card-enter">\n    <h3 style="font-size:15px;font-weight:700;margin-bottom:12px">📝 ${lang===\'hi\'?\'मेरे नोट्स\':\'My Notes\'}</h3>\n    ${Object.keys(notes).filter(k=>notes[k]).length===0?`<p style="font-size:13px;color:var(--muted);font-style:italic">${lang===\'hi\'?\'अभी कोई नोट नहीं। वेद पेज पर जाकर लिखें!\':\'No notes yet. Go to a Veda page to write some!\'}</p>`:\n    Object.keys(notes).filter(k=>notes[k]).map(k=>`<div style="margin-bottom:12px;padding:10px 14px;background:var(--cream);border-radius:var(--rs);border-left:3px solid var(--bds)">\n      <div style="font-size:11px;color:var(--muted);margin-bottom:4px">${k.startsWith(\'up_\')?\'उपनिषद — \'+k.replace(\'up_\',\'\'):k} — नोट</div>\n      <div style="font-size:13px;color:var(--soft);line-height:1.7">${notes[k]}</div>\n    </div>`).join(\'\')}\n  </div>`;\n}\n\n/* ────────── BOOKMARKS ────────── */\nfunction renderBookmarks(){\n  $(\'app\').innerHTML=`<div class="card card-enter">\n    <h2 style="font-size:17px;font-weight:700;margin-bottom:14px">🔖 ${lang===\'hi\'?\'मेरे बुकमार्क\':\'My Bookmarks\'}</h2>\n    ${bookmarks.length===0?`<p style="font-size:13px;color:var(--muted);font-style:italic">${lang===\'hi\'?\'कोई बुकमार्क नहीं। वेद या उपनिषद को 🏷 से सेव करें।\':\'No bookmarks yet. Save a Veda or Upanishad with the 🏷 button.\'}</p>`:\n    bookmarks.map(id=>{\n      const v=VEDAS.find(v=>v.id===id);\n      const u=UPANISHADS.find(u=>\'up_\'+u.id===id);\n      if(v) return `<div style="display:flex;align-items:center;gap:12px;padding:12px 14px;background:var(--cream);border-radius:var(--rs);margin-bottom:8px;cursor:pointer" onclick="setVeda(${VEDAS.indexOf(v)});showPage(\'home\')"><span style="font-size:22px">${v.icon}</span><div><div style="font-weight:600">${L(v.name)}</div><div style="font-size:11px;color:var(--muted)">${L(v.sub)}</div></div><button style="margin-left:auto;background:none;border:1px solid var(--bds);border-radius:8px;padding:4px 10px;cursor:pointer;font-size:12px" onclick="event.stopPropagation();toggleBM(\'${id}\')">✕ ${lang===\'hi\'?\'हटाएं\':\'Remove\'}</button></div>`;\n      if(u) return `<div style="display:flex;align-items:center;gap:12px;padding:12px 14px;background:var(--cream);border-radius:var(--rs);margin-bottom:8px;cursor:pointer" onclick="setUpIdx(${UPANISHADS.indexOf(u)});showPage(\'upanishads\')"><span style="font-size:22px">🧘</span><div><div style="font-weight:600">${L(u.name)}</div><div style="font-size:11px;color:${u.vedaColor}">${L(u.veda)}</div></div><button style="margin-left:auto;background:none;border:1px solid var(--bds);border-radius:8px;padding:4px 10px;cursor:pointer;font-size:12px" onclick="event.stopPropagation();toggleBM(\'${id}\')">✕ ${lang===\'hi\'?\'हटाएं\':\'Remove\'}</button></div>`;\n      return \'\';\n    }).join(\'\')}\n  </div>`;\n}\n\n/* ────────── SEARCH ────────── */\nlet searchIdx=[];\nfunction buildSearch(){\n  searchIdx=[];\n  VEDAS.forEach(v=>{\n    searchIdx.push({l:L(v.name)+\' — \'+L(v.sub),t:L(v.name),fn:()=>{setVeda(VEDAS.indexOf(v));showPage(\'home\')}});\n    Object.keys(v.ci).forEach(k=>{if(k.length<25)searchIdx.push({l:k,t:L(v.name),fn:()=>{setVeda(VEDAS.indexOf(v));activeConcept=k;showPage(\'home\')}})});\n  });\n  UPANISHADS.forEach(u=>searchIdx.push({l:L(u.name),t:L(u.veda),fn:()=>{setUpIdx(UPANISHADS.indexOf(u));showPage(\'upanishads\')}}));\n  RISHIS.forEach(r=>searchIdx.push({l:L(r.name)+\' \'+(lang===\'hi\'?\'ऋषि\':\'Sage\'),t:L(r.veda),fn:()=>{setRishi(RISHIS.indexOf(r));showPage(\'rishis\')}}));\n  DEITIES.forEach(d=>searchIdx.push({l:L(d.name)+\' — \'+L(d.role),t:lang===\'hi\'?\'देवता\':\'Deity\',fn:()=>{setDeity(DEITIES.indexOf(d));showPage(\'deities\')}}));\n}\nfunction doSearch(q){\n  if(!q.trim()){$(\'sr\').style.display=\'none\';return}\n  const m=searchIdx.filter(i=>i.l.toLowerCase().includes(q.toLowerCase())).slice(0,8);\n  const el=$(\'sr\');\n  if(!m.length){el.innerHTML=`<div class="sr-item" style="color:var(--muted)">${lang===\'hi\'?\'कोई नतीजा नहीं\':\'No results found\'}</div>`;el.style.display=\'block\';return}\n  el.innerHTML=m.map((x,i)=>`<div class="sr-item" onclick="searchIdx.filter(it=>it.l.toLowerCase().includes(\'${q.toLowerCase()}\'))[${i}]?.fn();$(\'si\').value=\'\';$(\'sr\').style.display=\'none\'">${x.l}<span class="sr-tag">${x.t}</span></div>`).join(\'\');\n  el.style.display=\'block\';\n}\n\n/* ────────── SETTERS ────────── */\nfunction setVeda(i){activeVeda=i;activeSection=0;activeConcept=null;activeUpanishad=null;showPage(\'home\',true)}\nfunction setSec(i){activeSection=i;activeConcept=null;activeUpanishad=null;showPage(\'home\',true)}\nfunction setConcept(c){activeConcept=activeConcept===c?null:c;showPage(\'home\',true)}\nfunction setUpIdx(i){activeUpanishad=activeUpanishad===i?null:i;activeUpTab=\'story\';if(currentPage===\'home\')showPage(\'home\',true);else showPage(\'upanishads\',true)}\nfunction setUpFilter(f){activeUpFilter=f;activeUpanishad=null;renderUpanishads()}\nfunction setUpTab(t){activeUpTab=t;if(currentPage===\'home\')showPage(\'home\',true);else renderUpanishads()}\nfunction setRishi(i){activeRishi=activeRishi===i?null:i;renderRishis()}\nfunction setDeity(i){activeDeity=activeDeity===i?null:i;renderDeities()}\n\n/* ────────── INIT ────────── */\n$(\'bmCount\').textContent=bookmarks.length;\nbuildSearch();\nshowPage(\'home\');\n</script>\n</body>\n</html>\n'

@app.route("/")
def index():
    return HTML

@app.route("/<path:path>")
def catch_all(path):
    return HTML
